        label.setGravity(Gravity.CENTER);
        label.setLetterSpacing(0.04f);
        nav.addView(label, new LinearLayout.LayoutParams(0, -2, 1));

        TextView next = dayNavButton("Next  ›");
        next.setOnClickListener(v -> shiftLiveDay(1));
