    // v252: a human label for the currently-shown live day (past, today, or future).
    private String liveDayLabel() {
        if (liveDayOffset == 0) return "Today";
        if (liveDayOffset == -1) return "Yesterday";
        if (liveDayOffset == 1) return "Tomorrow";
        Calendar cal = Calendar.getInstance();
        cal.add(Calendar.DAY_OF_YEAR, liveDayOffset);
        return new SimpleDateFormat("EEE, MMM d", Locale.US).format(cal.getTime());
    }

    // v252: change the shown day (past or future) and reload the slate.
    private void shiftLiveDay(int deltaDays) {
        liveDayOffset += deltaDays;
        renderLiveMatchupsPanel(); // reloads the Matchup-tab slate into standingsBox
    }

    private void renderHomeLiveMatchupsGames(ArrayList<LiveGame> games) {
        if (homeLiveMatchupsBox == null) return;
        lastRenderedSlate = games;
        homeLiveMatchupsBox.removeAllViews();
        int count = games == null ? 0 : games.size();
        renderHomeLiveHeader(homeLiveMatchupsBox, count <= 0 ? "See all" : count + " games");

        TextView sub = text("Jump straight into team, starter, or key-hitter comparisons.", 11, INK_DIM, false);
        sub.setPadding(0, dp(5), 0, 0);
        homeLiveMatchupsBox.addView(sub, matchWrap());

        if (games == null || games.isEmpty()) {
            TextView empty = text("No MLB games found for today. The Matchups tab still lets you build your own.", 11, INK_SOFT, true);
            empty.setGravity(Gravity.CENTER);
            empty.setPadding(dp(10), dp(13), dp(10), dp(13));
            empty.setBackground(roundedStroke(Color.argb(54, 255, 255, 255), Color.argb(54, 255, 255, 255), 18, 1));
            LinearLayout.LayoutParams emptyLp = matchWrap();
            emptyLp.setMargins(0, dp(10), 0, 0);
            homeLiveMatchupsBox.addView(empty, emptyLp);
            return;
        }

        LiveGame featured = pickFeaturedHomeGame(games);
        LinearLayout.LayoutParams featuredLp = new LinearLayout.LayoutParams(-1, dp(126));
        featuredLp.setMargins(0, dp(10), 0, 0);
        homeLiveMatchupsBox.addView(homeFeaturedLiveGameCard(featured), featuredLp);

        LinearLayout miniGrid = new LinearLayout(this);
        miniGrid.setOrientation(LinearLayout.VERTICAL);
        LinearLayout currentRow = null;
        int added = 0;
        for (LiveGame game : games) {
            if (game == null || game == featured) continue;
            if (added % 2 == 0) {
                currentRow = new LinearLayout(this);
                currentRow.setOrientation(LinearLayout.HORIZONTAL);
                LinearLayout.LayoutParams rowLp = matchWrap();
                rowLp.setMargins(0, added == 0 ? dp(9) : dp(7), 0, 0);
                miniGrid.addView(currentRow, rowLp);
            }
            LinearLayout.LayoutParams tileLp = new LinearLayout.LayoutParams(0, dp(86), 1);
            if (added % 2 == 1) tileLp.setMargins(dp(7), 0, 0, 0);
            currentRow.addView(homeMiniLiveGameTile(game), tileLp);
            added++;
            if (added >= 4) break;
        }
        if (added == 1 && currentRow != null) {
            Space spacer = new Space(this);
            LinearLayout.LayoutParams spacerLp = new LinearLayout.LayoutParams(0, dp(86), 1);
            spacerLp.setMargins(dp(7), 0, 0, 0);
            currentRow.addView(spacer, spacerLp);
        }
        if (added > 0) homeLiveMatchupsBox.addView(miniGrid, matchWrap());
    }

    private void renderHomeLiveMatchupsError(String message) {
        if (homeLiveMatchupsBox == null) return;
        homeLiveMatchupsBox.removeAllViews();
        renderHomeLiveHeader(homeLiveMatchupsBox, "Retry");
        TextView error = text("Could not load live games. Tap See all from the Matchups tab to try again. " + safe(message), 11, INK_SOFT, false);
        error.setPadding(dp(10), dp(12), dp(10), dp(12));
        error.setBackground(roundedStroke(Color.argb(54, 255, 255, 255), Color.argb(54, 255, 255, 255), 18, 1));
        LinearLayout.LayoutParams lp = matchWrap();
        lp.setMargins(0, dp(10), 0, 0);
        homeLiveMatchupsBox.addView(error, lp);
    }

    private LiveGame pickFeaturedHomeGame(ArrayList<LiveGame> games) {
        if (games == null || games.isEmpty()) return null;
        for (LiveGame game : games) {
            if (game != null && safe(game.abstractState).toLowerCase(Locale.US).contains("live")) return game;
        }
        for (LiveGame game : games) {
            if (game != null && !safe(game.abstractState).toLowerCase(Locale.US).contains("final")) return game;
        }
        return games.get(0);
    }


    private Team teamForLiveGame(int teamId, String name, String abbr) {
        Team t = findTeamById(teamId);
        if (t != null) return t;
        String safeName = safe(name);
        String safeAbbr = canonicalMlbAbbr(teamId, safeName, safe(abbr));
        if (teamId > 0 && !safeName.isEmpty()) return new Team(teamId, safeName, safeAbbr);
        if (!safeAbbr.isEmpty()) return new Team(teamId, safeName.isEmpty() ? safeAbbr : safeName, safeAbbr);
        return null;
    }

    private String capLogoFallback(Team team) {
        if (team == null) return "";
        String abbr = safe(team.abbr).toUpperCase(Locale.US).replaceAll("[^A-Z]", "");
        if (abbr.equals("LAD")) return "LA";
        if (abbr.equals("NYY") || abbr.equals("NYM")) return "NY";
        if (abbr.equals("BOS")) return "B";
        if (abbr.equals("CWS")) return "SOX";
        if (abbr.equals("WSH")) return "W";
        if (abbr.equals("ATH")) return "A";
        return abbr;
    }


    // v263: On the Home page, a start time is only useful before first pitch.
    // Once a game is live/final, show the actual score in the matchup headline and keep
    // the status pill focused on state ("In Progress" / "Final").
    private boolean homeLiveGameShouldShowScore(LiveGame game) {
        return game != null && !game.isPregame() && game.awayScore >= 0 && game.homeScore >= 0;
    }

    private String homeLiveGameStatusText(LiveGame game) {
        if (game == null) return "MLB";
        String status = game.statusLabel();
        if (game.isPregame()) {
            String time = safe(game.timeLabel());
            return status + (time.isEmpty() ? "" : " · " + time);
        }
        return status;
    }

    private String homeLiveGameHeadline(LiveGame game) {
        if (game == null) return "Live Matchups";
        String away = displayGameAbbr(game.awayTeamId, game.awayName, game.awayAbbr);
        String home = displayGameAbbr(game.homeTeamId, game.homeName, game.homeAbbr);
        if (homeLiveGameShouldShowScore(game)) {
            return away + " " + game.awayScoreText() + " @ " + home + " " + game.homeScoreText();
        }
        return away + " @ " + home;
    }


private View homeFeaturedLiveGameCard(LiveGame game) {
    Team away = game == null ? null : teamForLiveGame(game.awayTeamId, game.awayName, game.awayAbbr);
    Team home = game == null ? null : teamForLiveGame(game.homeTeamId, game.homeName, game.homeAbbr);
    TeamPalette awayPalette = game == null ? paletteForAbbr("MLB") : (away == null ? paletteForAbbr(game.awayAbbr) : paletteForTeam(away));
    TeamPalette homePalette = game == null ? paletteForAbbr("MLB") : (home == null ? paletteForAbbr(game.homeAbbr) : paletteForTeam(home));

    FrameLayout card = buildLiveLogoDuelShell(away, home, awayPalette, homePalette, 22, true, game == null ? null : () -> openHomeLiveGame(game));

    LinearLayout content = new LinearLayout(this);
    content.setOrientation(LinearLayout.VERTICAL);
    content.setPadding(dp(12), dp(10), dp(12), dp(10));
    card.addView(content, new FrameLayout.LayoutParams(-1, -1));

    LinearLayout top = new LinearLayout(this);
    top.setOrientation(LinearLayout.HORIZONTAL);
    top.setGravity(Gravity.CENTER_VERTICAL);
    TextView label = text("FEATURED GAME", 9, INK, true);
    label.setLetterSpacing(0.11f);
    top.addView(label, new LinearLayout.LayoutParams(0, -2, 1));
    String statusText = homeLiveGameStatusText(game);
    TextView status = text(statusText, 9, game == null ? Color.rgb(120, 220, 207) : statusColor(game), true);
    status.setGravity(Gravity.CENTER);
    status.setSingleLine(true);
    status.setEllipsize(TextUtils.TruncateAt.END);
    status.setPadding(dp(8), dp(4), dp(8), dp(4));
    int sc = game == null ? Color.rgb(120, 220, 207) : statusColor(game);
    status.setBackground(roundedStroke(Color.argb(86, 8, 13, 22), Color.argb(122, Color.red(sc), Color.green(sc), Color.blue(sc)), 13, 1));
    top.addView(status);
    content.addView(top, matchWrap());

    String title = homeLiveGameHeadline(game);
    TextView gameTitle = text(title, 27, Color.WHITE, true);
    gameTitle.setGravity(Gravity.CENTER);
    gameTitle.setLetterSpacing(0.02f);
    gameTitle.setPadding(0, dp(8), 0, 0);
    gameTitle.setShadowLayer(dp(2), 0, dp(1), Color.argb(170, 0, 0, 0));
    content.addView(gameTitle, matchWrap());

    String pitchers = game == null ? "Open today’s slate" : ((safe(game.awayPitcher).isEmpty() ? "Away SP TBD" : lastNameOnly(game.awayPitcher))
            + " vs " + (safe(game.homePitcher).isEmpty() ? "Home SP TBD" : lastNameOnly(game.homePitcher)));
    TextView sub = text(pitchers, 11, INK_SOFT, true);
    sub.setGravity(Gravity.CENTER);
    sub.setSingleLine(true);
    sub.setEllipsize(TextUtils.TruncateAt.END);
    sub.setPadding(0, dp(4), 0, 0);
    sub.setShadowLayer(dp(1.5f), 0, dp(1), Color.argb(140, 0, 0, 0));
    content.addView(sub, matchWrap());

    TextView cta = text("Open matchup options  ❯", 10, INK, true);
    cta.setGravity(Gravity.CENTER);
    cta.setPadding(0, dp(8), 0, 0);
    cta.setShadowLayer(dp(1.5f), 0, dp(1), Color.argb(150, 0, 0, 0));
    content.addView(cta, matchWrap());
    return card;
}



private View homeMiniLiveGameTile(LiveGame game) {
    Team away = teamForLiveGame(game.awayTeamId, game.awayName, game.awayAbbr);
    Team home = teamForLiveGame(game.homeTeamId, game.homeName, game.homeAbbr);
    TeamPalette awayPalette = away == null ? paletteForAbbr(game.awayAbbr) : paletteForTeam(away);
    TeamPalette homePalette = home == null ? paletteForAbbr(game.homeAbbr) : paletteForTeam(home);

    FrameLayout tile = buildLiveLogoDuelShell(away, home, awayPalette, homePalette, 18, false, () -> openHomeLiveGame(game));

    LinearLayout content = new LinearLayout(this);
    content.setOrientation(LinearLayout.VERTICAL);
    content.setGravity(Gravity.CENTER);
    content.setPadding(dp(9), dp(8), dp(9), dp(8));
    tile.addView(content, new FrameLayout.LayoutParams(-1, -1));

    TextView matchup = text(homeLiveGameHeadline(game), homeLiveGameShouldShowScore(game) ? 13 : 14, Color.WHITE, true);
    matchup.setGravity(Gravity.CENTER);
    matchup.setSingleLine(true);
    content.addView(matchup, matchWrap());

    TextView status = text(homeLiveGameStatusText(game), 8, statusColor(game), true);
    status.setGravity(Gravity.CENTER);
    status.setSingleLine(true);
    status.setEllipsize(TextUtils.TruncateAt.END);
    status.setPadding(0, dp(4), 0, 0);
    content.addView(status, matchWrap());

    String sp = (safe(game.awayPitcher).isEmpty() ? "TBD" : lastNameOnly(game.awayPitcher))
            + " / " + (safe(game.homePitcher).isEmpty() ? "TBD" : lastNameOnly(game.homePitcher));
    TextView pitchers = text(sp, 8, INK_DIM, false);
    pitchers.setGravity(Gravity.CENTER);
    pitchers.setSingleLine(true);
    pitchers.setEllipsize(TextUtils.TruncateAt.END);
    pitchers.setPadding(0, dp(2), 0, 0);
    content.addView(pitchers, matchWrap());
    return tile;
}



private FrameLayout buildLiveLogoDuelShell(Team away, Team home, TeamPalette awayPalette, TeamPalette homePalette, int radiusDp, boolean featured, Runnable clickAction) {
    FrameLayout shell = new FrameLayout(this);
    shell.setClipChildren(false);
    shell.setClipToPadding(false);
    shell.setClickable(clickAction != null);
    shell.setForeground(ripple(true));
    shell.setBackground(roundedGradientStroke(
            guardedDuelGradient(awayPalette, homePalette, featured),
            radiusDp,
            guardedDuelStroke(awayPalette, homePalette, featured ? 138 : 118),
            1));
    if (clickAction != null) shell.setOnClickListener(v -> clickAction.run());

    int awayColor = boostNeonColor(awayPalette.primary, featured ? 1.10f : 1.06f, featured ? 1.04f : 1.02f);
    int homeColor = boostNeonColor(homePalette.primary, featured ? 1.10f : 1.06f, featured ? 1.04f : 1.02f);
    int leftStrongA = featured ? 102 : 82;
    int leftStrongB = featured ? 62 : 48;
    int rightStrongA = featured ? 102 : 82;
    int rightStrongB = featured ? 62 : 48;

    View leftWash = new View(this);
    GradientDrawable leftG = new GradientDrawable(GradientDrawable.Orientation.LEFT_RIGHT,
            new int[] {
                    Color.argb(leftStrongA, Color.red(awayColor), Color.green(awayColor), Color.blue(awayColor)),
                    Color.argb(leftStrongB, Color.red(awayColor), Color.green(awayColor), Color.blue(awayColor)),
                    Color.argb(18, Color.red(awayColor), Color.green(awayColor), Color.blue(awayColor)),
                    Color.TRANSPARENT
            });
    leftG.setCornerRadius(dp(radiusDp));
    leftWash.setBackground(leftG);
    shell.addView(leftWash, new FrameLayout.LayoutParams(-1, -1));

    View rightWash = new View(this);
    GradientDrawable rightG = new GradientDrawable(GradientDrawable.Orientation.RIGHT_LEFT,
            new int[] {
                    Color.argb(rightStrongA, Color.red(homeColor), Color.green(homeColor), Color.blue(homeColor)),
                    Color.argb(rightStrongB, Color.red(homeColor), Color.green(homeColor), Color.blue(homeColor)),
                    Color.argb(18, Color.red(homeColor), Color.green(homeColor), Color.blue(homeColor)),
                    Color.TRANSPARENT
            });
    rightG.setCornerRadius(dp(radiusDp));
    rightWash.setBackground(rightG);
    shell.addView(rightWash, new FrameLayout.LayoutParams(-1, -1));

    View centerGuard = new View(this);
    GradientDrawable centerGuardBg = new GradientDrawable(GradientDrawable.Orientation.LEFT_RIGHT,
            new int[] { Color.TRANSPARENT, Color.argb(featured ? 186 : 168, 4, 8, 15), Color.TRANSPARENT });
    centerGuardBg.setCornerRadius(dp(28));
    centerGuard.setBackground(centerGuardBg);
    FrameLayout.LayoutParams guardLp = new FrameLayout.LayoutParams(dp(featured ? 134 : 96), -1);
    guardLp.gravity = Gravity.CENTER;
    guardLp.setMargins(0, dp(5), 0, dp(5));
    shell.addView(centerGuard, guardLp);

    View slash = new View(this);
    GradientDrawable slashBg = new GradientDrawable(GradientDrawable.Orientation.TOP_BOTTOM,
            new int[] { Color.argb(0, 255, 255, 255), Color.argb(featured ? 48 : 38, 255, 255, 255), Color.argb(0, 255, 255, 255) });
    slashBg.setCornerRadius(dp(3));
    slash.setBackground(slashBg);
    FrameLayout.LayoutParams slashLp = new FrameLayout.LayoutParams(dp(featured ? 4 : 3), dp(featured ? 148 : 104));
    slashLp.gravity = Gravity.CENTER;
    shell.addView(slash, slashLp);
    slash.setRotation(-28f);
    slash.setAlpha(featured ? 0.56f : 0.48f);

    // v243: subtle dark scrims behind the text columns so live-card copy stays readable
    // even on very bright team gradients. Team identity still comes from the gradients,
    // logos, and border glow; the scrims simply protect the text from blending in.
    View leftTextScrim = new View(this);
    GradientDrawable leftScrimBg = new GradientDrawable(GradientDrawable.Orientation.LEFT_RIGHT,
            new int[] { Color.argb(featured ? 132 : 144, 4, 8, 15), Color.argb(featured ? 88 : 92, 4, 8, 15), Color.TRANSPARENT });
    leftScrimBg.setCornerRadius(dp(radiusDp));
    leftTextScrim.setBackground(leftScrimBg);
    FrameLayout.LayoutParams leftScrimLp = new FrameLayout.LayoutParams(dp(featured ? 146 : 122), -1);
    leftScrimLp.gravity = Gravity.START;
    leftScrimLp.setMargins(dp(featured ? 6 : 4), dp(featured ? 6 : 5), 0, dp(featured ? 6 : 5));
    shell.addView(leftTextScrim, leftScrimLp);

    View rightTextScrim = new View(this);
    GradientDrawable rightScrimBg = new GradientDrawable(GradientDrawable.Orientation.RIGHT_LEFT,
            new int[] { Color.argb(featured ? 132 : 144, 4, 8, 15), Color.argb(featured ? 88 : 92, 4, 8, 15), Color.TRANSPARENT });
    rightScrimBg.setCornerRadius(dp(radiusDp));
    rightTextScrim.setBackground(rightScrimBg);
    FrameLayout.LayoutParams rightScrimLp = new FrameLayout.LayoutParams(dp(featured ? 146 : 122), -1);
    rightScrimLp.gravity = Gravity.END;
    rightScrimLp.setMargins(0, dp(featured ? 6 : 5), dp(featured ? 6 : 4), dp(featured ? 6 : 5));
    shell.addView(rightTextScrim, rightScrimLp);

    int logoSize = dp(featured ? 138 : 74);
    if (away != null) {
        // v242: remove the large faint city/abbr text watermark from live cards.
        // The team logos and explicit matchup label already carry identity, so the extra
        // background letters made the home live cards and live-matchup header feel busy.
        ImageView awayLogo = new ImageView(this);
        awayLogo.setScaleType(ImageView.ScaleType.FIT_CENTER);
        awayLogo.setAdjustViewBounds(true);
        awayLogo.setAlpha(featured ? 0.24f : 0.13f);
        FrameLayout.LayoutParams awayLp = new FrameLayout.LayoutParams(logoSize, logoSize);
        awayLp.gravity = Gravity.START | Gravity.CENTER_VERTICAL;
        awayLp.setMargins(dp(featured ? 10 : 3), dp(featured ? 18 : 8), 0, 0);
        shell.addView(awayLogo, awayLp);
        loadTeamLogo(away, awayLogo);
    }
    if (home != null) {
        ImageView homeLogo = new ImageView(this);
        homeLogo.setScaleType(ImageView.ScaleType.FIT_CENTER);
        homeLogo.setAdjustViewBounds(true);
        homeLogo.setAlpha(featured ? 0.24f : 0.13f);
        FrameLayout.LayoutParams homeLp = new FrameLayout.LayoutParams(logoSize, logoSize);
        homeLp.gravity = Gravity.END | Gravity.CENTER_VERTICAL;
        homeLp.setMargins(0, dp(featured ? 18 : 8), dp(featured ? 10 : 3), 0);
        shell.addView(homeLogo, homeLp);
        loadTeamLogo(home, homeLogo);
    }
    return shell;
}

    private void openHomeLiveGame(LiveGame game) {
        if (game == null) return;
        screenRequestToken++;
        activeLiveGameMenu = game;
        activePrimaryTab = TAB_MATCHUP;
        matchupPathMode = MATCHUP_PATH_LIVE;
        matchupResultMode = false;
        headToHeadMode = true;
        rankingsModeActive = false;
        expectedMode = false;
        hideKeyboard();
        if (homeBox != null) homeBox.setVisibility(View.GONE);
        if (form != null) form.setVisibility(View.GONE);
        if (resultsBox != null) resultsBox.setVisibility(View.GONE);
        if (standingsBox != null) standingsBox.setVisibility(View.VISIBLE);
        updateBottomNavSelection();
        updateAnalysisModeButtons();
        refreshMatchupHub();
        renderLiveGameMenu(game);
        if (mainScroll != null) mainScroll.post(() -> mainScroll.smoothScrollTo(0, 0));
    }


