        TextView tv = text("×", 13, INK, true);
        tv.setGravity(Gravity.CENTER);
        tv.setIncludeFontPadding(false);
        tv.setAlpha(0.88f);
        tv.setBackground(roundedStroke(Color.argb(122, 5, 9, 17), Color.argb(104, 255, 255, 255), 13, 1));
