    private int metricAccentColor(Metric m, Double delta) {
        if (delta == null || m.higherGood == null) return NAVY;
        boolean good = delta > 0;
        if (!m.higherGood) good = delta < 0;
        return good ? TEAL_DARK : SALMON;
    }

