    private void renderLiveMatchupGames(ArrayList<LiveGame> games) {
        if (standingsBox == null || activePrimaryTab != TAB_MATCHUP || matchupPathMode != MATCHUP_PATH_LIVE || matchupResultMode) return;
        lastRenderedSlate = games;
        standingsBox.removeAllViews();

        LinearLayout panel = new LinearLayout(this);
        panel.setOrientation(LinearLayout.VERTICAL);
        panel.setPadding(dp(12), dp(11), dp(12), dp(12));
        panel.setBackground(roundedGradientStroke(new int[] { Color.rgb(5, 9, 17), Color.rgb(10, 18, 32) }, 20, Color.argb(82, 255, 255, 255), 1));
        LinearLayout.LayoutParams panelLp = matchWrap();
        panelLp.setMargins(0, 0, 0, dp(8));

        LinearLayout titleRow = new LinearLayout(this);
        titleRow.setOrientation(LinearLayout.HORIZONTAL);
        titleRow.setGravity(Gravity.CENTER_VERTICAL);
        TextView title = text(liveDayOffset == 0 ? "TODAY'S LIVE MATCHUPS" : "LIVE MATCHUPS", 11, INK, true);
        title.setLetterSpacing(0.08f);
        titleRow.addView(title, new LinearLayout.LayoutParams(0, -2, 1));
        TextView count = text((games == null || games.isEmpty()) ? "Off day" : games.size() + " games", 9, Color.rgb(120, 220, 207), true);
        count.setGravity(Gravity.CENTER);
        count.setPadding(dp(8), dp(3), dp(8), dp(3));
        count.setBackground(roundedStroke(Color.argb(72, 13, 178, 163), Color.argb(124, 13, 178, 163), 14, 1));
        titleRow.addView(count);
        panel.addView(titleRow, matchWrap());

        panel.addView(buildLiveDayNav(), matchWrap());

        if (games == null || games.isEmpty()) {
            TextView empty = text("No MLB games found for " + (liveDayOffset == 0 ? "today" : liveDayLabel()) + ".", 12, INK_SOFT, true);
            empty.setGravity(Gravity.CENTER);
            empty.setPadding(dp(10), dp(12), dp(10), dp(12));
            empty.setBackground(roundedStroke(Color.argb(76, 8, 13, 22), Color.argb(52, 255, 255, 255), 14, 1));
            panel.addView(empty, matchWrap());
        } else {
            LinearLayout grid = new LinearLayout(this);
            grid.setOrientation(LinearLayout.VERTICAL);
            int i = 0;
            while (i < games.size()) {
                LinearLayout row = new LinearLayout(this);
                row.setOrientation(LinearLayout.HORIZONTAL);
                LinearLayout.LayoutParams rowLp = matchWrap();
                rowLp.setMargins(0, dp(6), 0, 0);
                panel.addView(row, rowLp);

                LinearLayout.LayoutParams leftLp = new LinearLayout.LayoutParams(0, dp(126), 1);
                row.addView(liveGameCard(games.get(i)), leftLp);
                if (i + 1 < games.size()) {
                    LinearLayout.LayoutParams rightLp = new LinearLayout.LayoutParams(0, dp(126), 1);
                    rightLp.setMargins(dp(7), 0, 0, 0);
                    row.addView(liveGameCard(games.get(i + 1)), rightLp);
                } else {
                    Space spacer = new Space(this);
                    LinearLayout.LayoutParams rightLp = new LinearLayout.LayoutParams(0, dp(126), 1);
                    rightLp.setMargins(dp(7), 0, 0, 0);
                    row.addView(spacer, rightLp);
                }
                i += 2;
            }
        }

        standingsBox.addView(panel, panelLp);
    }

