    LinearLayout line = new LinearLayout(this);
    line.setOrientation(LinearLayout.HORIZONTAL);
    line.setGravity(Gravity.CENTER_VERTICAL | (gravity == Gravity.RIGHT ? Gravity.RIGHT : Gravity.LEFT));
    TextView ab = text(safe(abbr).toUpperCase(Locale.US), 16, Color.WHITE, true);
    ab.setSingleLine(true); // v254: never let "BOS"/"NYM" wrap to B/O/S vertically
