    private int[] guardedDuelGradient(TeamPalette awayPalette, TeamPalette homePalette, boolean featured) {
        int dark = Color.rgb(5, 9, 17);
        int center = Color.rgb(3, 7, 14);
        int away = boostNeonColor(awayPalette.primary, featured ? 1.12f : 1.08f, featured ? 1.05f : 1.03f);
        int home = boostNeonColor(homePalette.primary, featured ? 1.12f : 1.08f, featured ? 1.05f : 1.03f);
        float sideDark = featured ? 0.34f : 0.42f;
        float fadeDark = featured ? 0.82f : 0.86f;
        return new int[] {
                mixColor(away, dark, sideDark),
                mixColor(away, dark, fadeDark),
                center,
                mixColor(home, dark, fadeDark),
                mixColor(home, dark, sideDark)
        };
    }

    private int guardedDuelStroke(TeamPalette awayPalette, TeamPalette homePalette, int alpha) {
        int away = ensureReadableColor(awayPalette.primary, 126);
        int home = ensureReadableColor(homePalette.primary, 126);
        int accent = mixColor(away, home, 0.50f);
        return Color.argb(alpha, Color.red(accent), Color.green(accent), Color.blue(accent));
    }



    private boolean isLiveFeedRefreshContext() {
        return activePrimaryTab == TAB_MATCHUP
                && matchupPathMode == MATCHUP_PATH_LIVE
                && activeLiveGameMenu != null
                && !matchupResultMode;
    }

    private void handleLiveFeedPullToRefresh(MotionEvent event) {
        if (event == null || mainScroll == null) return;
        if (!isLiveFeedRefreshContext()) {
            livePullRefreshArmed = false;
            return;
        }
        switch (event.getActionMasked()) {
            case MotionEvent.ACTION_DOWN:
                livePullRefreshArmed = mainScroll.getScrollY() <= 0;
                livePullRefreshStartY = event.getY();
                break;
            case MotionEvent.ACTION_MOVE:
                if (!livePullRefreshArmed || mainScroll.getScrollY() > 0) return;
                float pull = event.getY() - livePullRefreshStartY;
                long now = System.currentTimeMillis();
                if (pull > dp(82) && !liveRefreshInFlight && now - lastLivePullRefreshMs > 1500L) {
                    livePullRefreshArmed = false;
                    lastLivePullRefreshMs = now;
                    refreshLiveGameMenu(activeLiveGameMenu);
                }
                break;
            case MotionEvent.ACTION_UP:
            case MotionEvent.ACTION_CANCEL:
                livePullRefreshArmed = false;
                break;
        }
    }

    private void setLiveRefreshUiState(boolean refreshing) {
        // v270: the ↻ button spins continuously while refreshing, so it's obvious work is happening.
        TextView b = liveFeedRefreshButton;
        if (b == null) return;
        b.setEnabled(!refreshing);
        if (refreshing) {
            b.setText("↻");
            b.animate().cancel();
            b.setRotation(0f);
            b.animate().rotationBy(360f).setDuration(700)
                .setInterpolator(new android.view.animation.LinearInterpolator())
                .withEndAction(new Runnable() {
                    @Override public void run() {
                        if (liveRefreshInFlight && liveFeedRefreshButton != null) {
                            liveFeedRefreshButton.setRotation(0f);
                            liveFeedRefreshButton.animate().rotationBy(360f).setDuration(700)
                                .setInterpolator(new android.view.animation.LinearInterpolator())
                                .withEndAction(this).start();
                        }
                    }
                }).start();
            b.setAlpha(1f);
        } else {
            b.animate().cancel();
            b.animate().rotation(0f).setDuration(160).start();
        }
    }

    // Brief "Refreshed ✓" confirmation, then settle back to the ↻ icon.
    private void setLiveRefreshDone() {
        TextView b = liveFeedRefreshButton;
        if (b == null) return;
        b.animate().cancel();
        b.setEnabled(true);
        b.setRotation(0f);
        b.setText("✓");
        b.setTextColor(Color.rgb(82, 226, 176));
        b.setAlpha(1f);
        b.postDelayed(() -> {
            if (liveFeedRefreshButton != null && !liveRefreshInFlight) {
                liveFeedRefreshButton.animate().alpha(0f).setDuration(140).withEndAction(() -> {
                    if (liveFeedRefreshButton == null) return;
                    liveFeedRefreshButton.setText("↻");
                    liveFeedRefreshButton.setTextColor(INK);
                    liveFeedRefreshButton.animate().alpha(1f).setDuration(180).start();
                }).start();
            }
        }, 1100);
    }


    private void refreshLiveGameMenu(LiveGame game) {
        if (game == null || liveRefreshInFlight) return;
        liveRefreshInFlight = true;
        final int keepY = mainScroll == null ? 0 : mainScroll.getScrollY();
        setLiveRefreshUiState(true);
        // Gentle dim of current content while we fetch (single direction, no bounce).
        if (standingsBox != null) standingsBox.animate().alpha(0.55f).setDuration(160).start();
        io.execute(() -> {
            try {
                LiveGame fresh = fetchUpdatedLiveGame(game);
                if (fresh != null) copyLiveGameRefreshData(game, fresh);
                // Invalidate lazily-loaded sections so line score / win probability / key plays
                // all reload from scratch on the re-render (this is the "refresh everything" part).
                game.lineScoreLoaded = false;
                game.wpLoaded = false;
                game.lineInnings = new ArrayList<>();
                game.awayLineRuns = new ArrayList<>();
                game.homeLineRuns = new ArrayList<>();
                game.wpHomeSeries = new java.util.ArrayList<>();
                game.wpInnings = new java.util.ArrayList<>();
                game.wpDescriptions = new java.util.ArrayList<>();
                game.wpSwings = new java.util.ArrayList<>();
                main.post(() -> {
                    liveRefreshInFlight = false;
                    // Re-render while dimmed, then crossfade the fresh content in smoothly (one fade,
                    // from 0 → 1) so there's no flash of the tree being torn down and rebuilt.
                    renderLiveGameMenu(game);
                    if (mainScroll != null) mainScroll.post(() -> mainScroll.scrollTo(0, keepY));
                    if (standingsBox != null) {
                        standingsBox.setAlpha(0f);
                        standingsBox.animate().alpha(1f).setDuration(260).start();
                    }
                    setLiveRefreshDone();
                });
            } catch (Exception e) {
                main.post(() -> {
                    liveRefreshInFlight = false;
                    if (standingsBox != null) standingsBox.animate().alpha(1f).setDuration(160).start();
                    setLiveRefreshUiState(false);
                    Toast.makeText(this, "Couldn't refresh — check your connection", Toast.LENGTH_SHORT).show();
                });
            }
        });
    }

    private LiveGame fetchUpdatedLiveGame(LiveGame original) throws Exception {
        if (original == null) return null;
        String dateStr = scheduleDateForLiveGame(original);
        String url = "https://statsapi.mlb.com/api/v1/schedule?sportId=1&date=" + URLEncoder.encode(dateStr, "UTF-8") + "&hydrate=probablePitcher,linescore,team";
        JSONObject root = new JSONObject(httpGetFresh(url));
        JSONArray dates = root.optJSONArray("dates");
        if (dates == null) return null;
        for (int d = 0; d < dates.length(); d++) {
            JSONObject dateObj = dates.optJSONObject(d);
            if (dateObj == null) continue;
            JSONArray games = dateObj.optJSONArray("games");
            if (games == null) continue;
            for (int i = 0; i < games.length(); i++) {
                JSONObject g = games.optJSONObject(i);
                if (g != null && g.optInt("gamePk", 0) == original.gamePk) return parseLiveGameScheduleNode(g);
            }
        }
        return null;
    }

    private String scheduleDateForLiveGame(LiveGame game) {
        if (game != null && game.gameDate != null && !game.gameDate.isEmpty()) {
            try {
                SimpleDateFormat in = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'", Locale.US);
                in.setTimeZone(TimeZone.getTimeZone("UTC"));
                Date d = in.parse(game.gameDate);
                return new SimpleDateFormat("MM/dd/yyyy", Locale.US).format(d);
            } catch (Exception ignored) { }
        }
        return new SimpleDateFormat("MM/dd/yyyy", Locale.US).format(new Date());
    }

    private LiveGame parseLiveGameScheduleNode(JSONObject g) {
        if (g == null) return null;
        JSONObject teams = g.optJSONObject("teams");
        JSONObject awayNode = teams == null ? null : teams.optJSONObject("away");
        JSONObject homeNode = teams == null ? null : teams.optJSONObject("home");
        JSONObject awayTeam = awayNode == null ? null : awayNode.optJSONObject("team");
        JSONObject homeTeam = homeNode == null ? null : homeNode.optJSONObject("team");
        JSONObject status = g.optJSONObject("status");
        LiveGame live = new LiveGame();
        live.gamePk = g.optInt("gamePk", 0);
        live.gameDate = g.optString("gameDate", "");
        live.awayTeamId = awayTeam == null ? 0 : awayTeam.optInt("id", 0);
        live.homeTeamId = homeTeam == null ? 0 : homeTeam.optInt("id", 0);
        Team awayKnown = findTeamById(live.awayTeamId);
        Team homeKnown = findTeamById(live.homeTeamId);
        live.awayName = awayTeam == null ? "Away" : awayTeam.optString("name", "Away");
        live.homeName = homeTeam == null ? "Home" : homeTeam.optString("name", "Home");
        String awayApiAbbr = awayTeam == null ? "" : awayTeam.optString("abbreviation", awayTeam.optString("teamCode", ""));
        String homeApiAbbr = homeTeam == null ? "" : homeTeam.optString("abbreviation", homeTeam.optString("teamCode", ""));
        live.awayAbbr = canonicalMlbAbbr(live.awayTeamId, live.awayName, awayKnown == null ? awayApiAbbr : awayKnown.abbr);
        live.homeAbbr = canonicalMlbAbbr(live.homeTeamId, live.homeName, homeKnown == null ? homeApiAbbr : homeKnown.abbr);
        live.awayScore = awayNode == null ? -1 : awayNode.optInt("score", -1);
        live.homeScore = homeNode == null ? -1 : homeNode.optInt("score", -1);
        live.abstractState = status == null ? "" : status.optString("abstractGameState", "");
        live.detailedState = status == null ? "" : status.optString("detailedState", "");
        live.awayPitcher = pitcherName(awayNode == null ? null : awayNode.optJSONObject("probablePitcher"));
        live.homePitcher = pitcherName(homeNode == null ? null : homeNode.optJSONObject("probablePitcher"));
        live.awayRecord = recordFromNode(awayNode);
        live.homeRecord = recordFromNode(homeNode);
        // v331: capture live state from the hydrated linescore so the matchup tiles can show
        // inning · outs · baserunners for in-progress games.
        JSONObject ls = g.optJSONObject("linescore");
        if (ls != null) {
            live.sitInning = ls.optInt("currentInning", 0);
            live.sitInningState = ls.optString("inningState", "");
            live.sitOuts = ls.optInt("outs", 0);
            JSONObject off = ls.optJSONObject("offense");
            if (off != null) {
                live.onFirst = off.optJSONObject("first") != null;
                live.onSecond = off.optJSONObject("second") != null;
                live.onThird = off.optJSONObject("third") != null;
            }
        }
        return live;
    }

    private void copyLiveGameRefreshData(LiveGame target, LiveGame fresh) {
        if (target == null || fresh == null) return;
        target.gameDate = fresh.gameDate;
        target.awayTeamId = fresh.awayTeamId;
        target.homeTeamId = fresh.homeTeamId;
        target.awayName = fresh.awayName;
        target.homeName = fresh.homeName;
        target.awayAbbr = fresh.awayAbbr;
        target.homeAbbr = fresh.homeAbbr;
        target.awayPitcher = fresh.awayPitcher;
        target.homePitcher = fresh.homePitcher;
        target.awayRecord = fresh.awayRecord;
        target.homeRecord = fresh.homeRecord;
        target.awayScore = fresh.awayScore;
        target.homeScore = fresh.homeScore;
        target.abstractState = fresh.abstractState;
        target.detailedState = fresh.detailedState;
        target.sitInning = fresh.sitInning;
        target.sitInningState = fresh.sitInningState;
        target.sitOuts = fresh.sitOuts;
        target.onFirst = fresh.onFirst;
        target.onSecond = fresh.onSecond;
        target.onThird = fresh.onThird;
    }


    private int statusColor(LiveGame game) {
        String state = safe(game.abstractState).toLowerCase(Locale.US);
        String detail = safe(game.detailedState).toLowerCase(Locale.US);
        if (state.contains("live") || detail.contains("progress")) return Color.rgb(82, 226, 176);
        if (state.contains("final") || detail.contains("final")) return INK_SOFT;
        return Color.rgb(247, 197, 77);
    }


    private void renderLiveGameMenu(LiveGame game) {
        if (standingsBox == null || activePrimaryTab != TAB_MATCHUP) return;
        activeLiveGameMenu = game;
        // v335: when a game is final, default the live view to the dedicated FINAL celebration page
        // the first time we land on it. The user can still swipe into Tracker/Win Prob/Box Score.
        if ("Final".equals(game.statusLabel()) && !finalPageSeenFor(game.gamePk)) {
            gameHubTab = "live";
            gameHubLiveSub = "final";
            markFinalPageSeen(game.gamePk);
        }
        matchupPathMode = MATCHUP_PATH_LIVE;
        matchupResultMode = false;
        if (form != null) form.setVisibility(View.GONE);
        if (resultsBox != null) resultsBox.setVisibility(View.GONE);
        standingsBox.setVisibility(View.VISIBLE);
        standingsBox.removeAllViews();
        if (appBarView != null) appBarView.setVisibility(View.GONE);
        refreshMatchupHub();
        if (matchupHubBox != null) matchupHubBox.setVisibility(View.GONE); // v208: game hub owns this screen; no duplicate top path buttons

        Team away = teamForLiveGame(game.awayTeamId, game.awayName, game.awayAbbr);
        Team home = teamForLiveGame(game.homeTeamId, game.homeName, game.homeAbbr);
        TeamPalette awayPalette = away == null ? paletteForAbbr(game.awayAbbr) : paletteForTeam(away);
        TeamPalette homePalette = home == null ? paletteForAbbr(game.homeAbbr) : paletteForTeam(home);
        int accent = mixColor(awayPalette.primary, homePalette.primary, 0.50f);

        LinearLayout panel = new LinearLayout(this);
        panel.setOrientation(LinearLayout.VERTICAL);
        panel.setPadding(0, dp(2), 0, dp(12));
        panel.setBackground(roundedGradientStroke(
                guardedDuelGradient(awayPalette, homePalette, true),
                22,
                guardedDuelStroke(awayPalette, homePalette, 128),
                1));
        LinearLayout.LayoutParams panelLp = matchWrap();
        panelLp.setMargins(0, dp(9), 0, dp(8));
        standingsBox.addView(panel, panelLp);

        LinearLayout top = new LinearLayout(this);
        top.setOrientation(LinearLayout.HORIZONTAL);
        top.setGravity(Gravity.CENTER_VERTICAL);
        TextView back = text("‹ Games", 9, INK_SOFT, true);
        back.setGravity(Gravity.CENTER);
        back.setPadding(dp(7), dp(4), dp(7), dp(4));
        back.setBackground(roundedStroke(Color.argb(24, 255, 255, 255), Color.argb(48, 255, 255, 255), 999, 1));
        back.setForeground(ripple(true));
        back.setClickable(true);
        back.setOnClickListener(v -> openLiveMatchupsPath());
        top.addView(back);
        Space refreshSpacer = new Space(this);
        top.addView(refreshSpacer, new LinearLayout.LayoutParams(0, dp(1), 1));
        TextView livePill = text(game.isPregame() ? "GAME FEED" : "LIVE FEED", 9, game.isPregame() ? INK_DIM : Color.rgb(82, 226, 176), true);
        livePill.setGravity(Gravity.CENTER);
        livePill.setSingleLine(true);
        livePill.setLetterSpacing(0.08f);
        livePill.setPadding(dp(8), dp(4), dp(8), dp(4));
        livePill.setBackground(roundedStroke(Color.argb(game.isPregame() ? 22 : 42, 82, 226, 176), Color.argb(game.isPregame() ? 48 : 112, 82, 226, 176), 999, 1));
        top.addView(livePill);
        // v269: compact refresh control lives in the top bar (replaces the old instruction row).
        TextView topRefresh = text("↻", 14, INK, true);
        topRefresh.setGravity(Gravity.CENTER);
        topRefresh.setPadding(dp(8), dp(4), dp(8), dp(4));
        topRefresh.setBackground(roundedStroke(Color.argb(38, 255, 255, 255), Color.argb(70, 255, 255, 255), 999, 1));
        topRefresh.setForeground(ripple(true));
        topRefresh.setClickable(true);
        topRefresh.setEnabled(!liveRefreshInFlight);
        topRefresh.setAlpha(liveRefreshInFlight ? 0.42f : 1f);
        topRefresh.setOnClickListener(v -> refreshLiveGameMenu(game));
        liveFeedRefreshButton = topRefresh;
        LinearLayout.LayoutParams trLp = new LinearLayout.LayoutParams(-2, -2);
        trLp.setMargins(dp(6), 0, 0, 0);
        top.addView(topRefresh, trLp);
        if (game.isPregame()) panel.addView(top, matchWrap());

        String pitchers = (safe(game.awayPitcher).isEmpty() ? "Away SP TBD" : lastNameOnly(game.awayPitcher))
                + " vs " + (safe(game.homePitcher).isEmpty() ? "Home SP TBD" : lastNameOnly(game.homePitcher));

        // ===== v305: LIVE | MATCHUPS should be the first controls at the top =====
        // Hide the utility header on live game detail so the main tab bar sits at the very top,
        // and keep switching between LIVE and MATCHUPS stable without layout jumps.
        boolean pregame = game.isPregame();
        boolean live = game.isLive();
        if (gameHubTabDirty || gameHubTab == null) {
            gameHubTab = live ? "live" : "matchups";
            gameHubTabDirty = false;
        }
        if (pregame) gameHubTab = "matchups";
        if (!live && "live".equals(gameHubTab)) gameHubTab = "matchups";
        if ("box".equals(gameHubTab)) gameHubTab = live ? "live" : "matchups";

        boolean controlsAboveHero = !pregame && live;
        boolean liveHubSelected = "live".equals(gameHubTab);
        if (controlsAboveHero) {
            panel.addView(gameHubTabBar(game, awayPalette, homePalette), tabBarLp());
        }

        if (game.isLive()) {
            // v305: LIVE keeps the Tracker/Win Prob/Box sub-tabs; MATCHUPS hides them completely.
            // Both routes still keep the main LIVE | MATCHUPS switch at the very top.
            LinearLayout liveCard = new LinearLayout(this);
            liveCard.setOrientation(LinearLayout.VERTICAL);
            liveCard.setPadding(dp(2), dp(2), dp(2), dp(4));
            liveCard.setBackground(roundedStroke(Color.argb(150, 6, 11, 20), Color.argb(46, 255, 255, 255), 20, 1));
            LinearLayout.LayoutParams cardLp = matchWrap();
            cardLp.setMargins(dp(12), controlsAboveHero ? 0 : dp(6), dp(12), dp(4));
            if (liveHubSelected) {
                liveCard.addView(liveSubBar(game), matchWrap());
            }
            View liveHero = liveScoreHero(game, away, home, awayPalette, homePalette);
            LinearLayout.LayoutParams lhLp = matchWrap();
            lhLp.setMargins(0, liveHubSelected ? dp(1) : 0, 0, 0);
            liveCard.addView(liveHero, lhLp);
            panel.addView(liveCard, cardLp);
        } else {
            LinearLayout.LayoutParams heroLp = matchWrap();
            heroLp.setMargins(dp(12), dp(2), dp(12), dp(8));
            panel.addView(liveScoreHero(game, away, home, awayPalette, homePalette), heroLp);
        }

        if (!pregame && !controlsAboveHero) {
            panel.addView(gameHubTabBar(game, awayPalette, homePalette), tabBarLp());
        }

        if ("matchups".equals(gameHubTab)) {
            if (game.isLive()) {
                // v334: on a live game's MATCHUPS view, dragging RIGHT carousels to the LIVE tab.
                // (Live → Matchups is NOT a drag — Live owns its own AB/sub-tab carousel.)
                LinearLayout mHost = new LinearLayout(this);
                mHost.setOrientation(LinearLayout.VERTICAL);
                renderMatchupCards(mHost, game, awayPalette, homePalette, accent);
                SwipePagerFrame mWrap = wrapMatchupsToLive(game, mHost);
                panel.addView(mWrap, matchWrap());
            } else {
                renderMatchupCards(panel, game, awayPalette, homePalette, accent);
            }
        } else {
            renderLiveTab(panel, game, awayPalette, homePalette, false); // sub-bar now lives in the live card header
        }
    }

    private LinearLayout.LayoutParams tabBarLp() {
        LinearLayout.LayoutParams lp = matchWrap();
        lp.setMargins(dp(12), 0, dp(12), dp(8));
        return lp;
    }

    // The LIVE | MATCHUPS | BOX top-level switch.
    private View gameHubTabBar(LiveGame game, TeamPalette awayPalette, TeamPalette homePalette) {
        boolean live = game.isLive();
        LinearLayout bar = new LinearLayout(this);
        bar.setOrientation(LinearLayout.HORIZONTAL);
        bar.setPadding(dp(4), dp(4), dp(4), dp(4));
        bar.setBackground(roundedStroke(Color.argb(150, 6, 11, 20), Color.argb(60, 255, 255, 255), 16, 1));
        if (live) bar.addView(gameHubTabButton("LIVE", "live", Color.rgb(82, 226, 176), game));
        bar.addView(gameHubTabButton("MATCHUPS", "matchups", Color.rgb(247, 197, 77), game));
        gameHubTabBarView = bar;
        return bar;
    }

    // v301: unified, natural tab switching. Re-render, then keep the tab bar exactly where it was
    // on screen so content swaps in place — unless the bar was scrolled above the top, in which
    // case snap it to the top so the tabs + the start of the new content are both visible. Never
    // jumps to an arbitrary position.
    private void switchGameHubView(LiveGame game) {
        final int beforeY = mainScroll == null ? 0 : mainScroll.getScrollY();
        final int barBefore = gameHubTabBarView == null ? 0 : gameHubTabBarView.getTop();
        renderLiveGameMenu(game);
        if (mainScroll == null) return;
        mainScroll.post(() -> {
            int barAfter = gameHubTabBarView == null ? barBefore : gameHubTabBarView.getTop();
            // Where the bar sat in the viewport before the switch (top of bar minus old scroll).
            int barViewportY = barBefore - beforeY;
            // Keep the bar at that same viewport position after the re-render.
            int target = barAfter - barViewportY;
            int max = Math.max(0, mainScroll.getChildAt(0).getHeight() - mainScroll.getHeight());
            if (target < 0) target = 0;
            if (target > max) target = max;
            mainScroll.scrollTo(0, target);
        });
    }

    private View gameHubTabButton(String label, String key, int accent, LiveGame game) {
        boolean active = key.equals(gameHubTab);
        TextView t = text(label, 11, active ? Color.rgb(8, 13, 22) : INK_SOFT, true);
        t.setGravity(Gravity.CENTER);
        t.setLetterSpacing(0.06f);
        t.setSingleLine(true);
        t.setPadding(dp(6), dp(10), dp(6), dp(10));
        t.setLayoutParams(new LinearLayout.LayoutParams(0, -2, 1));
        if (active) {
            t.setBackground(roundedGradientStroke(new int[] {
                    accent, mixColor(accent, Color.WHITE, 0.18f)
            }, 12, Color.argb(0, 0, 0, 0), 0));
        } else {
            t.setForeground(ripple(true));
            t.setClickable(true);
            t.setOnClickListener(v -> {
                gameHubTab = key;
                switchGameHubView(game);
            });
        }
        return t;
    }

    private LinearLayout.LayoutParams liveSubBarLp() {
        LinearLayout.LayoutParams lp = matchWrap();
        lp.setMargins(dp(12), 0, dp(12), dp(6));
        return lp;
    }

    private View liveSubBar(LiveGame game) {
        LinearLayout sub = new LinearLayout(this);
        sub.setOrientation(LinearLayout.HORIZONTAL);
        sub.setPadding(dp(3), dp(3), dp(3), dp(3));
        sub.setBackground(roundedStroke(Color.argb(120, 6, 11, 20), Color.argb(44, 255, 255, 255), 999, 1));
        if ("Final".equals(game.statusLabel())) sub.addView(liveSubButton("Final", "final", game));
        sub.addView(liveSubButton("Tracker", "tracker", game));
        sub.addView(liveSubButton("Win Prob", "prob", game));
        sub.addView(liveSubButton("Box Score", "box", game));
        return sub;
    }

    // ---- LIVE tab: tracker (default) with a sub-switch to Win Prob / Line ----
    private void renderLiveTab(LinearLayout panel, LiveGame game, TeamPalette awayPalette, TeamPalette homePalette, boolean showSubBar) {
        if (showSubBar) {
            panel.addView(liveSubBar(game), liveSubBarLp());
        }

        if ("final".equals(gameHubLiveSub) && "Final".equals(game.statusLabel())) {
            LinearLayout finalHost = new LinearLayout(this);
            finalHost.setOrientation(LinearLayout.VERTICAL);
            finalHost.addView(finalGamePage(game, awayPalette, homePalette), matchWrap());
            SwipePagerFrame swipeWrap = wrapInSubTabSwiper(game, finalHost, false, true); // Tracker→
            LinearLayout.LayoutParams fLp = matchWrap(); fLp.setMargins(dp(12), 0, dp(12), dp(6));
            panel.addView(swipeWrap, fLp);
        } else if ("prob".equals(gameHubLiveSub)) {
            LinearLayout wpHost = new LinearLayout(this);
            wpHost.setOrientation(LinearLayout.VERTICAL);
            loadWinProbability(game, wpHost, awayPalette, homePalette);
            SwipePagerFrame swipeWrap = wrapInSubTabSwiper(game, wpHost, true, true); // ←Tracker  Box→
            LinearLayout.LayoutParams wpLp = matchWrap(); wpLp.setMargins(dp(12), 0, dp(12), dp(6));
            panel.addView(swipeWrap, wpLp);
        } else if ("box".equals(gameHubLiveSub)) {
            LinearLayout boxHost = new LinearLayout(this);
            boxHost.setOrientation(LinearLayout.VERTICAL);
            renderBoxTab(boxHost, game, awayPalette, homePalette);
            SwipePagerFrame swipeWrap = wrapInSubTabSwiper(game, boxHost, true, false); // ←Win Prob only
            panel.addView(swipeWrap, matchWrap()); // renderBoxTab already insets its own host
        } else {
            LinearLayout trackerHost = new LinearLayout(this);
            trackerHost.setOrientation(LinearLayout.VERTICAL);
            trackerHost.setVisibility(View.GONE);
            LinearLayout.LayoutParams thLp = matchWrap(); thLp.setMargins(dp(12), 0, dp(12), dp(6));
            panel.addView(trackerHost, thLp);
            activeLiveTrackerHost = trackerHost;
            activeLiveTrackerAwayPal = awayPalette;
            activeLiveTrackerHomePal = homePalette;
            activeLiveTrackerGame = game;
            loadLiveTracker(game, trackerHost, awayPalette, homePalette);
            startLiveTrackerPolling(game);
        }
    }

    private View liveSubButton(String label, String key, LiveGame game) {
        boolean active = key.equals(gameHubLiveSub);
        TextView t = text(label, 10, active ? Color.rgb(8, 13, 22) : INK_SOFT, true);
        t.setGravity(Gravity.CENTER);
        t.setSingleLine(true);
        t.setPadding(dp(6), dp(7), dp(6), dp(7));
        t.setLayoutParams(new LinearLayout.LayoutParams(0, -2, 1));
        if (active) {
            t.setBackground(roundedStroke(Color.rgb(214, 226, 240), Color.argb(0, 0, 0, 0), 999, 0));
        } else {
            t.setForeground(ripple(true)); t.setClickable(true);
            t.setOnClickListener(v -> {
                if (!"tracker".equals(key)) stopLiveTrackerPolling();
                gameHubLiveSub = key;
                switchGameHubView(game);
            });
        }
        return t;
    }

    // ---- BOX tab: full box score inline ----
    private void renderBoxTab(LinearLayout panel, LiveGame game, TeamPalette awayPalette, TeamPalette homePalette) {
        stopLiveTrackerPolling();
        LinearLayout host = new LinearLayout(this);
        host.setOrientation(LinearLayout.VERTICAL);
        LinearLayout.LayoutParams hLp = matchWrap(); hLp.setMargins(dp(12), 0, dp(12), dp(6));
        panel.addView(host, hLp);
        TextView loading = text("Loading box score…", 11, INK_DIM, false);
        loading.setPadding(dp(4), dp(8), 0, dp(8));
        host.addView(loading, matchWrap());
        io.execute(() -> {
            try { fetchCompactLineScoreInto(game); } catch (Exception ignored) { }
            JSONObject box = null;
            try { box = new JSONObject(httpGet("https://statsapi.mlb.com/api/v1/game/" + game.gamePk + "/boxscore")); } catch (Exception ignored) { }
            final JSONObject fbox = box;
            main.post(() -> {
                if (host.getParent() == null) return;
                host.removeAllViews();
                if (fbox == null) { host.addView(text("Box score unavailable.", 11, INK_DIM, false), matchWrap()); return; }
                // Line score at the top of the Box Score tab — the inning-by-inning R/H/E grid.
                if (game.lineInnings != null && !game.lineInnings.isEmpty()) {
                    View ls = compactLineScoreCard(game, awayPalette, homePalette);
                    LinearLayout.LayoutParams lsLp = matchWrap(); lsLp.setMargins(0, 0, 0, dp(8));
                    host.addView(ls, lsLp);
                }
                host.addView(buildBoxScoreSheet(game, fbox, awayPalette, homePalette), matchWrap());
            });
        });
    }

    // ---- MATCHUPS tab: the signature matchup cards ----
    private void renderMatchupCards(LinearLayout panel, LiveGame game, TeamPalette awayPalette, TeamPalette homePalette, int accent) {
        stopLiveTrackerPolling();
        addMatchupHubSection(panel, "COMPLETE", "Broadest read");
        LinearLayout.LayoutParams overallLp = new LinearLayout.LayoutParams(-1, dp(82));
        overallLp.setMargins(dp(12), 0, dp(12), dp(3));
        panel.addView(gameMenuTile("Team Overall", displayGameAbbr(game.awayTeamId, game.awayName, game.awayAbbr) + " vs " + displayGameAbbr(game.homeTeamId, game.homeName, game.homeAbbr), "Composite edge across record, lineup, and prevention", accent, v -> openLiveTeamMatchup(game)), overallLp);

        addMatchupHubSection(panel, "TEAM UNITS", "Offense · pitching · bullpen");
        LinearLayout unitRow = matchupHubTileRow(panel);
        unitRow.addView(gameMenuTile("Team Offense", "Lineup vs lineup", "Runs, discipline, and contact quality", Color.rgb(99, 166, 255), v -> openLiveTeamOffenseMatchup(game)), new LinearLayout.LayoutParams(0, -1, 1));
        LinearLayout.LayoutParams pdLp = new LinearLayout.LayoutParams(0, -1, 1);
        pdLp.setMargins(dp(7), 0, 0, 0);
        unitRow.addView(gameMenuTile("Pitching/Defense", "Staff prevention", "Run prevention and contact allowed", Color.rgb(120, 220, 207), v -> openLiveTeamPitchingDefenseMatchup(game)), pdLp);
        LinearLayout.LayoutParams bullpenLp = new LinearLayout.LayoutParams(-1, dp(82));
        bullpenLp.setMargins(dp(12), 0, dp(12), dp(3));
        panel.addView(gameMenuTile("Bullpens", "Reliever edge", "Freshness + quality by available arms", Color.rgb(120, 220, 207), v -> openLiveBullpenMatchup(game)), bullpenLp);

        addMatchupHubSection(panel, "GAME MATCHUPS", "Today-specific");
        boolean probablesKnown = !safe(game.awayPitcher).isEmpty() && !safe(game.homePitcher).isEmpty();
        String pitchers = (safe(game.awayPitcher).isEmpty() ? "Away SP TBD" : lastNameOnly(game.awayPitcher))
                + " vs " + (safe(game.homePitcher).isEmpty() ? "Home SP TBD" : lastNameOnly(game.homePitcher));
        LinearLayout gameRow = matchupHubTileRow(panel);
        gameRow.addView(gameMenuTile("Starting Pitchers", probablesKnown ? pitchers : "Pitchers TBD", "Probable starter duel", Color.rgb(247, 197, 77), v -> openLivePitcherMatchup(game), probablesKnown, "Probable starters not posted yet"), new LinearLayout.LayoutParams(0, -1, 1));
        LinearLayout.LayoutParams ovsLp = new LinearLayout.LayoutParams(0, -1, 1);
        ovsLp.setMargins(dp(7), 0, 0, 0);
        gameRow.addView(gameMenuTile("Offense vs SP", probablesKnown ? "Lineups vs probable starters" : "Pitchers TBD", "Fixed model built for this game", Color.rgb(255, 155, 92), v -> openLiveOffenseVsStarterMatchup(game), probablesKnown, "Probable starters not posted yet"), ovsLp);

        addMatchupHubSection(panel, "PLAYER SPOTLIGHTS", "Top bats · recent form");
        LinearLayout hitterRow = matchupHubTileRow(panel);
        hitterRow.addView(gameMenuTile("Key Hitters", "Active season bats", "Best available hitter per team", Color.rgb(99, 166, 255), v -> openLiveTopHitterMatchup(game)), new LinearLayout.LayoutParams(0, -1, 1));
        LinearLayout.LayoutParams hotLp = new LinearLayout.LayoutParams(0, -1, 1);
        hotLp.setMargins(dp(7), 0, 0, 0);
        hitterRow.addView(gameMenuTile("Hot Bats", "Recent-form hitters", "Who is swinging it well lately", Color.rgb(255, 109, 131), v -> openLiveHotBatsMatchup(game)), hotLp);
    }

    private View gameMatchupHeroCard(LiveGame game, Team away, Team home, TeamPalette awayPalette, TeamPalette homePalette, String pitchers) {
        FrameLayout hero = buildLiveLogoDuelShell(away, home, awayPalette, homePalette, 24, true, null);
        hero.setMinimumHeight(dp(108));

        LinearLayout content = new LinearLayout(this);
        content.setOrientation(LinearLayout.VERTICAL);
        content.setPadding(dp(14), dp(7), dp(14), dp(6));
        hero.addView(content, new FrameLayout.LayoutParams(-1, -1));

        LinearLayout top = new LinearLayout(this);
        top.setOrientation(LinearLayout.HORIZONTAL);
        top.setGravity(Gravity.CENTER_VERTICAL);
        TextView label = text("GAME MATCHUP HUB", 8, INK, true);
        label.setLetterSpacing(0.14f);
        top.addView(label, new LinearLayout.LayoutParams(0, -2, 1));
        int sc = statusColor(game);
        // v246: same rule as the grid — start time only shown pre-game, since it's meaningless
        // (and confusing) once a game is live or final.
        String statusText = game.isPregame() && !safe(game.timeLabel()).isEmpty()
                ? game.statusLabel() + " · " + game.timeLabel()
                : game.statusLabel();
        TextView status = text(statusText, 8, sc, true);
        status.setGravity(Gravity.CENTER);
        status.setSingleLine(true);
        status.setEllipsize(TextUtils.TruncateAt.END);
        status.setPadding(dp(8), dp(3), dp(8), dp(3));
        status.setBackground(roundedStroke(Color.argb(86, 8, 13, 22), Color.argb(122, Color.red(sc), Color.green(sc), Color.blue(sc)), 13, 1));
        top.addView(status);
        content.addView(top, matchWrap());

        String awayAbbr = displayGameAbbr(game.awayTeamId, game.awayName, game.awayAbbr);
        String homeAbbr = displayGameAbbr(game.homeTeamId, game.homeName, game.homeAbbr);
        // v246: 24sp dominated the screen whose job is choosing a matchup type. 21sp keeps the
        // title prominent without overpowering the menu below it.
        TextView title = text(awayAbbr + "  @  " + homeAbbr, 21, Color.WHITE, true);
        title.setGravity(Gravity.CENTER);
        title.setLetterSpacing(0.04f);
        title.setPadding(0, dp(5), 0, 0);
        content.addView(title, matchWrap());

        TextView sp = text(pitchers, 11, INK_SOFT, true);
        sp.setGravity(Gravity.CENTER);
        sp.setSingleLine(true);
        sp.setEllipsize(TextUtils.TruncateAt.END);
        sp.setPadding(0, dp(2), 0, 0);
        content.addView(sp, matchWrap());

        return hero;
    }

    // v277: compact, score-forward hero for live games — team logos on the outside, big score
    // numbers flanking center, and a center column carrying inning · bases · count · outs.
    private View liveScoreHero(LiveGame game, Team away, Team home, TeamPalette awayPalette, TeamPalette homePalette) {
        int awayColor = ensureReadableColor(awayPalette.primary, 150);
        int homeColor = ensureReadableColor(homePalette.primary, 150);

        FrameLayout shell = new FrameLayout(this);
        shell.setBackground(roundedGradientStroke(new int[] {
                mixColor(awayPalette.primary, Color.rgb(8, 12, 20), 0.45f),
                Color.rgb(8, 12, 20),
                mixColor(homePalette.primary, Color.rgb(8, 12, 20), 0.45f)
        }, 22, guardedDuelStroke(awayPalette, homePalette, 150), 1));

        LinearLayout row = new LinearLayout(this);
        row.setOrientation(LinearLayout.HORIZONTAL);
        row.setGravity(Gravity.CENTER_VERTICAL);
        row.setPadding(dp(12), dp(6), dp(12), dp(6));

        row.addView(heroTeamBlock(away, displayGameAbbr(game.awayTeamId, game.awayName, game.awayAbbr), game.awayRecord, awayColor, true), new LinearLayout.LayoutParams(0, -2, 2.1f));

        if (game.isLive()) {
            // away score
            TextView aScore = text(game.awayScore < 0 ? "0" : String.valueOf(game.awayScore), 34, Color.WHITE, true);
            aScore.setGravity(Gravity.CENTER);
            row.addView(aScore, new LinearLayout.LayoutParams(0, -2, 1.1f));

            // center: inning only; situation details live in the tracker board.
            LinearLayout center = new LinearLayout(this);
            center.setOrientation(LinearLayout.VERTICAL);
            center.setGravity(Gravity.CENTER);
            row.addView(center, new LinearLayout.LayoutParams(0, -2, 2.4f));
            fillHeroCenter(center, game, awayPalette, homePalette);
            loadHeroCenter(game, center, awayPalette, homePalette);

            TextView hScore = text(game.homeScore < 0 ? "0" : String.valueOf(game.homeScore), 34, Color.WHITE, true);
            hScore.setGravity(Gravity.CENTER);
            row.addView(hScore, new LinearLayout.LayoutParams(0, -2, 1.1f));
        } else {
            // Pregame/final uses the same hero shell and side team blocks, but the center
            // becomes time/status + probable pitching matchup instead of scores/inning.
            LinearLayout center = new LinearLayout(this);
            center.setOrientation(LinearLayout.VERTICAL);
            center.setGravity(Gravity.CENTER);
            row.addView(center, new LinearLayout.LayoutParams(0, -2, 3.7f));

            String primary = game.isPregame() && !safe(game.timeLabel()).isEmpty()
                    ? game.timeLabel()
                    : game.statusLabel();
            TextView time = text(primary, 15, statusColor(game), true);
            time.setGravity(Gravity.CENTER);
            time.setSingleLine(true);
            time.setEllipsize(TextUtils.TruncateAt.END);
            center.addView(time, matchWrap());

            String awayP = safe(game.awayPitcher).isEmpty() ? "Away SP TBD" : lastNameOnly(game.awayPitcher);
            String homeP = safe(game.homePitcher).isEmpty() ? "Home SP TBD" : lastNameOnly(game.homePitcher);
            TextView pit = text(awayP + " vs " + homeP, 10, INK_SOFT, true);
            pit.setGravity(Gravity.CENTER);
            pit.setSingleLine(true);
            pit.setEllipsize(TextUtils.TruncateAt.END);
            pit.setPadding(0, dp(3), 0, 0);
            center.addView(pit, matchWrap());
        }

        row.addView(heroTeamBlock(home, displayGameAbbr(game.homeTeamId, game.homeName, game.homeAbbr), game.homeRecord, homeColor, false), new LinearLayout.LayoutParams(0, -2, 2.1f));

        shell.addView(row, new FrameLayout.LayoutParams(-1, -2));
        return shell;
    }

    private View heroTeamBlock(Team team, String abbr, String record, int color, boolean logoFirst) {
        LinearLayout block = new LinearLayout(this);
        block.setOrientation(LinearLayout.VERTICAL);
        block.setGravity(Gravity.CENTER);
        ImageView logo = new ImageView(this);
        logo.setScaleType(ImageView.ScaleType.FIT_CENTER);
        if (team != null) loadTeamLogo(team, logo);
        block.addView(logo, new LinearLayout.LayoutParams(dp(36), dp(36)));
        TextView ab = text(abbr, 14, Color.WHITE, true);
        ab.setSingleLine(true); ab.setGravity(Gravity.CENTER); ab.setPadding(0, dp(2), 0, 0);
        block.addView(ab, matchWrap());
        if (!safe(record).isEmpty()) {
            TextView rec = text(record, 9, INK_DIM, true);
            rec.setSingleLine(true); rec.setGravity(Gravity.CENTER);
            block.addView(rec, matchWrap());
        }
        return block;
    }

    private void fillHeroCenter(LinearLayout center, LiveGame game, TeamPalette awayPalette, TeamPalette homePalette) {
        center.removeAllViews();
        boolean topHalf = safe(game.sitInningState).toLowerCase(Locale.US).contains("top")
                || safe(game.sitInningState).toLowerCase(Locale.US).contains("middle");
        int batColor = ensureReadableColor((topHalf ? awayPalette : homePalette).primary, 165);
        // Just the inning, prominent — bases/count/outs now live in the situation board.
        String arrow = game.sitInning > 0 ? (topHalf ? "▲ " : "▼ ") : "";
        String inningStr = game.sitInning > 0 ? (topHalf ? "Top " : "Bot ") + ordinalNum(game.sitInning) : game.statusLabel();
        TextView ar = text(arrow, 11, batColor, true);
        ar.setGravity(Gravity.CENTER);
        center.addView(ar, matchWrap());
        TextView inn = text(inningStr, 16, batColor, true);
        inn.setGravity(Gravity.CENTER);
        inn.setSingleLine(true);
        center.addView(inn, matchWrap());
    }

    private void loadHeroCenter(LiveGame game, LinearLayout center, TeamPalette awayPalette, TeamPalette homePalette) {
        if (game == null || !game.isLive()) return;
        io.execute(() -> {
            try {
                String body = httpGetFresh("https://statsapi.mlb.com/api/v1/game/" + game.gamePk + "/linescore");
                if (body != null && !body.trim().isEmpty()) parseLiveSituation(new JSONObject(body), game);
            } catch (Exception ignored) { }
            main.post(() -> { if (center.getParent() != null) fillHeroCenter(center, game, awayPalette, homePalette); });
        });
    }

