    private boolean bullpenValueIsMuted(String value) {
        String v = safe(value).trim();
        return v.isEmpty() || "—".equals(v) || v.equals("0") || v.equals("0.0") || v.equals("0.0 / 0");
    }



    private String bullpenEdgeLabel(BullpenReport away, BullpenReport home) {
        String q = bullpenQualityWinnerLabel(away, home);
        String f = bullpenFreshnessWinnerLabel(away, home);
        if ("Even".equals(q) && "Even".equals(f)) return "Bullpen edge: Even";
        if (q.equals(f)) return "Bullpen edge: " + q;
        if (!"Even".equals(q)) return "Quality edge: " + q + " · Freshness edge: " + f;
        return "Freshness edge: " + f;
    }


    private double bullpenOverallScore(BullpenReport r) {
        if (r == null || !r.qualityAvailable()) return Double.NaN;
        double era = safeMetric(r.era(), 4.50d);
        double whip = safeMetric(r.whip(), 1.35d);
        double kbb = safeMetric(r.kMinusBbPct(), 11.0d);
        double hr9 = safeMetric(r.hr9(), 1.10d);
        double recentEra = safeMetric(r.recent30Era(), era);
        double recentKbb = safeMetric(r.recent14KMinusBbPct(), kbb);
        return 100.0d - (era * 4.5d) - (whip * 7.0d) + (kbb * 0.85d) - (hr9 * 3.0d)
                - (recentEra * 2.2d) + (recentKbb * 0.55d) - (r.fatiguePenalty() * 2.0d);
    }

    private double safeMetric(double v, double fallback) {
        return Double.isNaN(v) ? fallback : v;
    }

    private int compareLower(double a, double b) {
        if (Double.isNaN(a) || Double.isNaN(b) || Math.abs(a - b) < 0.0001d) return 0;
        return a < b ? -1 : 1;
    }

    private int compareHigher(double a, double b) {
        if (Double.isNaN(a) || Double.isNaN(b) || Math.abs(a - b) < 0.0001d) return 0;
        return a > b ? -1 : 1;
    }

    private String bullpenFmt(double value, int decimals) {
        if (Double.isNaN(value)) return "—";
        String pattern = decimals <= 0 ? "0" : (decimals == 1 ? "0.0" : "0.00");
        return new DecimalFormat(pattern).format(value);
    }



    private String bullpenIpFmt(double ip) {
        if (Double.isNaN(ip)) return "—";
        int outs = (int) Math.round(Math.max(0.0d, ip) * 3.0d);
        if (outs <= 0) return "—";
        return (outs / 3) + "." + (outs % 3);
    }

    private String bullpenIpPitches(double ip, int pitches) {
        int outs = Double.isNaN(ip) ? 0 : (int) Math.round(Math.max(0.0d, ip) * 3.0d);
        if (outs <= 0 && pitches <= 0) return "—";
        return bullpenIpFmt(ip) + " / " + pitches;
    }





    private BullpenReport fetchBullpenReport(Team team, int season, int excludeGamePk) {
        if (team == null) return new BullpenReport("—", "Unknown");
        BullpenReport report = new BullpenReport(team.abbr, team.name);
        mergeAppearanceBullpenFromSchedule(report, team, season, excludeGamePk);
        if (!report.qualityAvailable()) {
            report.qualitySource = "Reliever proxy fallback";
            mergeBullpenSeasonQuality(report, team, season);
        }
        report.finalizeFatigue();
        return report;
    }




    private void mergeAppearanceBullpenFromSchedule(BullpenReport report, Team team, int season, int excludeGamePk) {
        if (report == null || team == null || team.id <= 0) return;
        try {
            String start = bullpenSeasonStartDate(season);
            String end = bullpenSeasonEndDate(season);
            ArrayList<ScheduleGameRef> games = fetchCompletedTeamGames(team, start, end, excludeGamePk, true);
            if (games.isEmpty()) games = fetchCompletedTeamGames(team, start, end, excludeGamePk, false);
            int startIndex = Math.max(0, games.size() - 90);
            // v200: this loop previously fetched each boxscore one-by-one — up to 90 serial HTTP
            // round trips per team (~180 per matchup card), which is why the bullpen card was so
            // slow. Completed games are immutable, so each game's parsed relief appearances are
            // now cached permanently (repeat opens read tiny local JSONs and only fetch games
            // completed since the last view), and first-time fetches run 8 wide. daysAgo is
            // recomputed from the game date at merge time so freshness stays correct no matter
            // when the cache entry was written. v220 keeps fatigue calendar-day based, so off days
            // correctly reset B2B and pitch-count stress decays by actual days since usage.
            ExecutorService pool = Executors.newFixedThreadPool(8);
            ArrayList<Future<ArrayList<BullpenAppearanceRecord>>> futures = new ArrayList<>();
            for (int i = startIndex; i < games.size(); i++) {
                final ScheduleGameRef g = games.get(i);
                if (g == null) continue;
                futures.add(pool.submit(() -> bullpenAppearancesForGame(team, g.gamePk, g.dateKey)));
            }
            for (Future<ArrayList<BullpenAppearanceRecord>> f : futures) {
                try {
                    for (BullpenAppearanceRecord r : f.get()) {
                        report.addAppearance(r.dateKey, daysAgoFromDateKey(r.dateKey), r.pitcherId, r.pitcherName,
                                r.ip, r.pitches, r.er, r.hits, r.walks, r.k, r.bf, r.hr, r.runs, r.bulk, r.longRelief);
                    }
                } catch (Exception ignored) {}
            }
            pool.shutdown();
            report.qualitySource = "Appearance-based";
        } catch (Exception ignored) {}
    }

    static class BullpenAppearanceRecord {
        final String dateKey; final int pitcherId; final String pitcherName;
        final double ip; final int pitches;
        final double er, hits, walks, k, bf, hr, runs;
        final boolean bulk, longRelief;
        BullpenAppearanceRecord(String dateKey, int pitcherId, String pitcherName, double ip, int pitches,
                                double er, double hits, double walks, double k, double bf, double hr, double runs,
                                boolean bulk, boolean longRelief) {
            this.dateKey = dateKey; this.pitcherId = pitcherId; this.pitcherName = pitcherName;
            this.ip = ip; this.pitches = pitches;
            this.er = er; this.hits = hits; this.walks = walks; this.k = k;
            this.bf = bf; this.hr = hr; this.runs = runs;
            this.bulk = bulk; this.longRelief = longRelief;
        }
    }

    // v200: per-(game, team) relief appearances. Cache hit = tiny local JSON; miss = boxscore
    // fetch + parse, then cached permanently since completed games never change. A successful
    // parse with no relief work caches an empty list; a fetch/parse FAILURE is never cached.
    private ArrayList<BullpenAppearanceRecord> bullpenAppearancesForGame(Team team, int gamePk, String dateKey) {
        String cacheKey = "bpapp_" + gamePk + "_" + team.id;
        ArrayList<BullpenAppearanceRecord> cached = loadCachedBullpenAppearances(cacheKey);
        if (cached != null) return cached;
        ArrayList<BullpenAppearanceRecord> parsed = parseBullpenAppearancesFromBoxscore(team, gamePk, dateKey);
        if (parsed != null) {
            saveCachedBullpenAppearances(cacheKey, parsed);
            return parsed;
        }
        return new ArrayList<>();
    }

    private File bullpenAppearanceCacheFile(String key) {
        File dir = new File(getCacheDir(), "bullpen_apps");
        dir.mkdirs();
        return new File(dir, key + ".json");
    }

    private ArrayList<BullpenAppearanceRecord> loadCachedBullpenAppearances(String key) {
        try {
            File f = bullpenAppearanceCacheFile(key);
            if (!f.exists()) return null;
            String text = readCacheFile(f);
            if (text == null || text.isEmpty()) return null;
            JSONObject root = new JSONObject(text);
            JSONArray arr = root.optJSONArray("appearances");
            if (arr == null) return null;
            ArrayList<BullpenAppearanceRecord> out = new ArrayList<>();
            for (int i = 0; i < arr.length(); i++) {
                JSONObject o = arr.optJSONObject(i);
                if (o == null) continue;
                out.add(new BullpenAppearanceRecord(
                        o.optString("date", ""), o.optInt("pid", 0), o.optString("name", ""),
                        o.optDouble("ip", 0), o.optInt("pitches", 0),
                        o.optDouble("er", 0), o.optDouble("h", 0), o.optDouble("bb", 0), o.optDouble("k", 0),
                        o.optDouble("bf", 0), o.optDouble("hr", 0), o.optDouble("r", 0),
                        o.optBoolean("bulk", false), o.optBoolean("long", false)));
            }
            return out;
        } catch (Exception e) {
            return null;
        }
    }

    private void saveCachedBullpenAppearances(String key, ArrayList<BullpenAppearanceRecord> records) {
        try {
            JSONArray arr = new JSONArray();
            for (BullpenAppearanceRecord r : records) {
                JSONObject o = new JSONObject();
                o.put("date", r.dateKey); o.put("pid", r.pitcherId); o.put("name", r.pitcherName);
                o.put("ip", r.ip); o.put("pitches", r.pitches);
                o.put("er", r.er); o.put("h", r.hits); o.put("bb", r.walks); o.put("k", r.k);
                o.put("bf", r.bf); o.put("hr", r.hr); o.put("r", r.runs);
                o.put("bulk", r.bulk); o.put("long", r.longRelief);
                arr.put(o);
            }
            JSONObject root = new JSONObject();
            root.put("appearances", arr);
            writeCacheFile(bullpenAppearanceCacheFile(key), root.toString());
        } catch (Exception ignored) {}
    }

    private ArrayList<ScheduleGameRef> fetchCompletedTeamGames(Team team, String start, String end, int excludeGamePk, boolean regularOnly) {
        ArrayList<ScheduleGameRef> out = new ArrayList<>();
        if (team == null || team.id <= 0) return out;
        try {
            String url = "https://statsapi.mlb.com/api/v1/schedule?sportId=1&teamId=" + team.id
                    + "&startDate=" + URLEncoder.encode(start, "UTF-8")
                    + "&endDate=" + URLEncoder.encode(end, "UTF-8")
                    + (regularOnly ? "&gameTypes=R" : "");
            JSONObject root = new JSONObject(httpGet(url));
            JSONArray dates = root.optJSONArray("dates");
            if (dates == null) return out;
            for (int d = 0; d < dates.length(); d++) {
                JSONObject dateObj = dates.optJSONObject(d);
                if (dateObj == null) continue;
                String dateKey = safe(dateObj.optString("date", ""));
                JSONArray games = dateObj.optJSONArray("games");
                if (games == null) continue;
                for (int i = 0; i < games.length(); i++) {
                    JSONObject game = games.optJSONObject(i);
                    if (game == null) continue;
                    int gamePk = game.optInt("gamePk", 0);
                    if (gamePk <= 0 || gamePk == excludeGamePk) continue;
                    if (!isCompletedGame(game)) continue;
                    out.add(new ScheduleGameRef(gamePk, dateKey));
                }
            }
        } catch (Exception ignored) {}
        return out;
    }

    private boolean isCompletedGame(JSONObject game) {
        if (game == null) return false;
        JSONObject status = game.optJSONObject("status");
        String state = safe(status == null ? "" : status.optString("abstractGameState", "")).toLowerCase(Locale.US);
        String detail = safe(status == null ? "" : status.optString("detailedState", "")).toLowerCase(Locale.US);
        return state.contains("final") || detail.contains("final") || detail.contains("completed");
    }

    private String bullpenSeasonStartDate(int season) {
        return "03/20/" + Math.max(2015, season);
    }

    private String bullpenSeasonEndDate(int season) {
        int current = Calendar.getInstance().get(Calendar.YEAR);
        if (season >= current) return scheduleDate(addDays(new Date(), -1));
        return "11/15/" + season;
    }


    // v200: was mergeBullpenAppearancesFromBoxscore. Now a pure parser safe to run on worker
    // threads (the report is only mutated on the collecting thread): returns the game's relief
    // appearance records, an empty list for a valid boxscore with no relief work, or null on
    // fetch/parse failure so failures are never cached as absence.
    private ArrayList<BullpenAppearanceRecord> parseBullpenAppearancesFromBoxscore(Team team, int gamePk, String dateKey) {
        if (team == null || gamePk <= 0) return new ArrayList<>();
        try {
            String boxUrl = "https://statsapi.mlb.com/api/v1/game/" + gamePk + "/boxscore";
            JSONObject box = new JSONObject(httpGet(boxUrl));
            // Single-use ~200KB payload: the parsed records are what gets cached, so don't let
            // up to 180 of these accumulate in the in-memory text cache for the whole session.
            textCache.remove(boxUrl);
            ArrayList<BullpenAppearanceRecord> out = new ArrayList<>();
            JSONObject teamsObj = box.optJSONObject("teams");
            if (teamsObj == null) return out;
            JSONObject side = null;
            JSONObject away = teamsObj.optJSONObject("away");
            JSONObject home = teamsObj.optJSONObject("home");
            if (away != null && teamMatchesBoxscoreTeam(away.optJSONObject("team"), team)) side = away;
            else if (home != null && teamMatchesBoxscoreTeam(home.optJSONObject("team"), team)) side = home;
            if (side == null) return out;

            JSONArray pitchers = side.optJSONArray("pitchers");
            JSONObject players = side.optJSONObject("players");
            if (pitchers == null || players == null || pitchers.length() == 0) return out;

            HashSet<Integer> starterIds = starterPitcherIdsFromBoxscore(pitchers, players);
            int firstPitcherId = pitchers.optInt(0, 0);
            JSONObject firstPitching = pitchingLineForPlayer(players, firstPitcherId);
            double firstIp = firstPitching == null ? 0.0d : inningsToDouble(firstPitching.optString("inningsPitched", "0"));
            int firstPitches = firstPitching == null ? 0 : intFromJsonAny(firstPitching, "pitchesThrown", "numberOfPitches", "pitches", "NP");
            boolean openerGame = firstPitcherId > 0 && starterIds.contains(firstPitcherId)
                    && pitchers.length() >= 4
                    && (firstIp <= 2.0d || firstPitches <= 35);

            for (int i = 0; i < pitchers.length(); i++) {
                int pid = pitchers.optInt(i, 0);
                if (pid <= 0 || starterIds.contains(pid)) continue;
                JSONObject pObj = players.optJSONObject("ID" + pid);
                JSONObject pitching = pitchingLineForPlayer(players, pid);
                if (pitching == null) continue;

                double ip = inningsToDouble(pitching.optString("inningsPitched", "0"));
                int pitches = intFromJsonAny(pitching, "pitchesThrown", "numberOfPitches", "pitches", "NP");
                if (ip <= 0.0d && pitches <= 0) continue;

                int er = intFromJsonAny(pitching, "earnedRuns", "earnedRunsAllowed", "er", "ER");
                int hits = intFromJsonAny(pitching, "hits", "hitsAllowed", "h", "H");
                int bb = intFromJsonAny(pitching, "baseOnBalls", "walks", "bb", "BB");
                int k = intFromJsonAny(pitching, "strikeOuts", "strikeouts", "so", "SO");
                int bf = intFromJsonAny(pitching, "battersFaced", "bf", "BF");
                int hr = intFromJsonAny(pitching, "homeRuns", "homeRunsAllowed", "hr", "HR");
                int runs = intFromJsonAny(pitching, "runs", "runsAllowed", "r", "R");

                boolean bulk = isBulkReliefAppearance(openerGame, i, ip, pitches);
                boolean longRelief = isLongReliefAppearance(bulk, ip, pitches);
                out.add(new BullpenAppearanceRecord(dateKey, pid, pitcherNameFromBoxscore(pObj), ip, pitches,
                        er, hits, bb, k, bf, hr, runs, bulk, longRelief));
            }
            return out;
        } catch (Exception e) {
            return null;
        }
    }



    private HashSet<Integer> starterPitcherIdsFromBoxscore(JSONArray pitchers, JSONObject players) {
        HashSet<Integer> starterIds = new HashSet<>();
        if (pitchers == null || players == null) return starterIds;
        int firstPitcherId = pitchers.optInt(0, 0);
        for (int i = 0; i < pitchers.length(); i++) {
            int pid = pitchers.optInt(i, 0);
            if (pid <= 0) continue;
            JSONObject pObj = players.optJSONObject("ID" + pid);
            if (pObj == null) continue;
            JSONObject stats = pObj.optJSONObject("stats");
            JSONObject pitching = stats == null ? null : stats.optJSONObject("pitching");
            if (pitching == null) continue;
            int gs = intFromJsonAny(pitching, "gamesStarted", "gamesStartedPitching", "gs", "GS");
            if (gs > 0) starterIds.add(pid);
        }
        if (starterIds.isEmpty() && firstPitcherId > 0) starterIds.add(firstPitcherId);
        return starterIds;
    }


    private JSONObject pitchingLineForPlayer(JSONObject players, int pitcherId) {
        if (players == null || pitcherId <= 0) return null;
        JSONObject pObj = players.optJSONObject("ID" + pitcherId);
        if (pObj == null) return null;
        JSONObject stats = pObj.optJSONObject("stats");
        return stats == null ? null : stats.optJSONObject("pitching");
    }


    private String pitcherNameFromBoxscore(JSONObject playerObj) {
        if (playerObj == null) return "";
        JSONObject person = playerObj.optJSONObject("person");
        String full = person == null ? "" : safe(person.optString("fullName", ""));
        if (!full.isEmpty()) return full;
        return safe(playerObj.optString("fullName", playerObj.optString("lastName", "")));
    }

    private boolean isBulkReliefAppearance(boolean openerGame, int orderIndex, double ip, int pitches) {
        return openerGame && orderIndex == 1 && (ip >= 2.0d || pitches >= 35);
    }

    private boolean isLongReliefAppearance(boolean bulk, double ip, int pitches) {
        return !bulk && (ip >= 3.0d || pitches >= 50);
    }



    private void mergeBullpenSeasonQuality(BullpenReport report, Team team, int season) {
        if (report == null || team == null || team.id <= 0) return;
        try {
            String url = "https://statsapi.mlb.com/api/v1/stats?stats=season&group=pitching&playerPool=ALL&season="
                    + season + "&teamId=" + team.id + "&limit=10000";
            JSONObject root = new JSONObject(httpGet(url));
            JSONArray statsArr = root.optJSONArray("stats");
            if (statsArr == null || statsArr.length() == 0) return;
            JSONArray splits = statsArr.optJSONObject(0) == null ? null : statsArr.optJSONObject(0).optJSONArray("splits");
            if (splits == null) return;

            for (int i = 0; i < splits.length(); i++) {
                JSONObject split = splits.optJSONObject(i);
                if (split == null) continue;
                JSONObject stat = split.optJSONObject("stat");
                if (stat == null) continue;

                int starts = intFromJsonAny(stat, "gamesStarted", "gamesStartedPitching", "gs", "GS");
                if (starts > 0) continue;

                // Do not let partial/summary rows create fake 0.00 ERA or blank baselines.
                if (!jsonHasAny(stat, "inningsPitched") || !jsonHasAny(stat, "earnedRuns", "runs", "hits", "baseOnBalls", "strikeOuts")) continue;

                double ip = inningsToDouble(stat.optString("inningsPitched", "0"));
                if (ip <= 0.0d) continue;

                int er = intFromJsonAny(stat, "earnedRuns", "earnedRunsAllowed", "er", "ER");
                int hits = intFromJsonAny(stat, "hits", "hitsAllowed", "h", "H");
                int bb = intFromJsonAny(stat, "baseOnBalls", "walks", "bb", "BB");
                int k = intFromJsonAny(stat, "strikeOuts", "strikeouts", "so", "SO");
                int bf = intFromJsonAny(stat, "battersFaced", "bf", "BF");
                int hr = intFromJsonAny(stat, "homeRuns", "homeRunsAllowed", "hr", "HR");
                int runs = intFromJsonAny(stat, "runs", "runsAllowed", "r", "R");
                int pitches = intFromJsonAny(stat, "pitchesThrown", "numberOfPitches", "pitches", "NP");

                report.addSeason(ip, er, hits, bb, k, bf, hr, runs, pitches);
            }
        } catch (Exception ignored) {}
    }



    private void mergeRecentBullpenUsage(BullpenReport report, Team team, int excludeGamePk) {
        if (report == null || team == null || team.id <= 0) return;
        try {
            Date now = new Date();
            String start = scheduleDate(addDays(now, -4));
            String end = scheduleDate(addDays(now, -1));
            String url = "https://statsapi.mlb.com/api/v1/schedule?sportId=1&teamId=" + team.id
                    + "&startDate=" + URLEncoder.encode(start, "UTF-8")
                    + "&endDate=" + URLEncoder.encode(end, "UTF-8");
            JSONObject root = new JSONObject(httpGet(url));
            JSONArray dates = root.optJSONArray("dates");
            if (dates == null) return;
            for (int d = 0; d < dates.length(); d++) {
                JSONObject dateObj = dates.optJSONObject(d);
                if (dateObj == null) continue;
                String dateKey = safe(dateObj.optString("date", ""));
                int daysAgo = daysAgoFromDateKey(dateKey);
                if (daysAgo < 1 || daysAgo > 3) continue;
                JSONArray games = dateObj.optJSONArray("games");
                if (games == null) continue;
                for (int i = 0; i < games.length(); i++) {
                    JSONObject game = games.optJSONObject(i);
                    if (game == null) continue;
                    int gamePk = game.optInt("gamePk", 0);
                    if (gamePk <= 0 || gamePk == excludeGamePk) continue;
                    JSONObject status = game.optJSONObject("status");
                    String state = safe(status == null ? "" : status.optString("abstractGameState", "")).toLowerCase(Locale.US);
                    String detail = safe(status == null ? "" : status.optString("detailedState", "")).toLowerCase(Locale.US);
                    if (!(state.contains("final") || detail.contains("final") || detail.contains("completed"))) continue;
                    mergeBullpenUsageFromBoxscore(report, team, gamePk, dateKey, daysAgo);
                }
            }
        } catch (Exception ignored) {}
    }




    private void mergeBullpenUsageFromBoxscore(BullpenReport report, Team team, int gamePk, String dateKey, int daysAgo) {
        // v200: routes through the same cached per-(game, team) appearance records as the main
        // appearance path, so the recent-usage fallback also skips re-fetching boxscores.
        if (report == null) return;
        for (BullpenAppearanceRecord r : bullpenAppearancesForGame(team, gamePk, dateKey)) {
            report.addAppearance(r.dateKey, daysAgo, r.pitcherId, r.pitcherName,
                    r.ip, r.pitches, r.er, r.hits, r.walks, r.k, r.bf, r.hr, r.runs, r.bulk, r.longRelief);
        }
    }



    private boolean teamMatchesBoxscoreTeam(JSONObject obj, Team team) {
        if (obj == null || team == null) return false;
        int id = obj.optInt("id", 0);
        if (id > 0 && id == team.id) return true;
        String abbr = canonicalMlbAbbr(id, obj.optString("name", ""), obj.optString("abbreviation", obj.optString("teamCode", "")));
        return safe(abbr).equalsIgnoreCase(team.abbr);
    }

    private Date addDays(Date base, int days) {
        Calendar cal = Calendar.getInstance();
        cal.setTime(base == null ? new Date() : base);
        cal.add(Calendar.DATE, days);
        return cal.getTime();
    }

    private String scheduleDate(Date date) {
        return new SimpleDateFormat("MM/dd/yyyy", Locale.US).format(date == null ? new Date() : date);
    }

    private int daysAgoFromDateKey(String key) {
        try {
            SimpleDateFormat fmt = new SimpleDateFormat("yyyy-MM-dd", Locale.US);
            Calendar target = Calendar.getInstance();
            target.setTime(fmt.parse(key));
            zeroTime(target);
            Calendar today = Calendar.getInstance();
            zeroTime(today);
            long diff = today.getTimeInMillis() - target.getTimeInMillis();
            return (int) Math.round(diff / (24d * 60d * 60d * 1000d));
        } catch (Exception e) {
            return 99;
        }
    }

    private void zeroTime(Calendar cal) {
        if (cal == null) return;
        cal.set(Calendar.HOUR_OF_DAY, 0);
        cal.set(Calendar.MINUTE, 0);
        cal.set(Calendar.SECOND, 0);
        cal.set(Calendar.MILLISECOND, 0);
    }

    private double valueOrZero(Double v) {
        return v == null || Double.isNaN(v) ? 0.0d : v;
    }



