    private ArrayList<Metric> offenseVsStarterMetrics() {
        ArrayList<Metric> out = new ArrayList<>();
        out.add(new Metric("ovsOverall", "Matchup Score", "", 0, true, "rate", "matchup", "both"));
        out.add(new Metric("ovsOnBase", "On-Base Edge", "", 0, true, "rate", "matchup", "both"));
        out.add(new Metric("ovsPower", "Power Edge", "", 0, true, "rate", "matchup", "both"));
        out.add(new Metric("ovsDiscipline", "Discipline Edge", "", 0, true, "rate", "matchup", "both"));
        out.add(new Metric("ovsStarterVuln", "Starter Stress", "", 0, true, "rate", "matchup", "both"));
        return out;
    }

    private void addMetricIfPresent(ArrayList<Metric> out, String key) {
        Metric m = findMetricByKey(key);
        if (m != null) out.add(m);
    }

    private double scoreRange(Double value, double low, double high, boolean higherGood) {
        if (value == null || Double.isNaN(value)) return 50d;
        if (high <= low) return 50d;
        double pct = clamp01((value - low) / (high - low));
        if (!higherGood) pct = 1d - pct;
        return pct * 100d;
    }

    private double clamp01(double value) {
        if (Double.isNaN(value)) return 0d;
        return Math.max(0d, Math.min(1d, value));
    }

    private double mean(double... values) {
        if (values == null || values.length == 0) return 0d;
        double sum = 0d;
        int count = 0;
        for (double v : values) {
            if (Double.isNaN(v)) continue;
            sum += v;
            count++;
        }
        return count == 0 ? 0d : sum / count;
    }

    private LeaderboardEntry topHitterForTeam(ArrayList<LeaderboardEntry> entries, Team team) {
        if (entries == null || team == null) return null;
        Metric ops = metricByKey("ops");
        HashSet<Integer> activeIds = activeRosterPlayerIds(team);
        int minPa = keyHitterMinimumPa(currentSeason());
        LeaderboardEntry best = null;
        LeaderboardEntry fallback = null;
        for (LeaderboardEntry e : entries) {
            if (e == null || e.stats == null) continue;
            if (!team.key().equals(teamKeyFromEntry(e))) continue;
            Player p = playerFromEntry(e);
            if (p == null || isPitcher(p)) continue;
            Double value = e.stats.get("ops");
            if (value == null || Double.isNaN(value)) continue;
            if (fallback == null || compareMetricValues(value, fallback.stats.get("ops"), ops) < 0) fallback = e;
            if (!isLiveHitterEligible(e, p, activeIds, minPa)) continue;
            if (best == null || compareMetricValues(value, best.stats.get("ops"), ops) < 0) best = e;
        }
        return best != null ? best : fallback;
    }

    private final Map<Integer, HashSet<Integer>> activeRosterIdCache = new HashMap<>();

    private HashSet<Integer> activeRosterPlayerIds(Team team) {
        HashSet<Integer> empty = new HashSet<>();
        if (team == null || team.id <= 0) return empty;
        HashSet<Integer> cached = activeRosterIdCache.get(team.id);
        if (cached != null) return cached;
        HashSet<Integer> ids = new HashSet<>();
        try {
            String url = "https://statsapi.mlb.com/api/v1/teams/" + team.id + "/roster?rosterType=active";
            JSONObject root = new JSONObject(httpGet(url));
            JSONArray roster = root.optJSONArray("roster");
            if (roster != null) {
                for (int i = 0; i < roster.length(); i++) {
                    JSONObject row = roster.optJSONObject(i);
                    JSONObject person = row == null ? null : row.optJSONObject("person");
                    int id = person == null ? 0 : person.optInt("id", 0);
                    if (id > 0) ids.add(id);
                }
            }
        } catch (Exception ignored) {}
        activeRosterIdCache.put(team.id, ids);
        return ids;
    }

    private int keyHitterMinimumPa(int season) {
        Calendar now = Calendar.getInstance();
        int current = now.get(Calendar.YEAR);
        if (season < current) return 100;
        Calendar opening = Calendar.getInstance();
        opening.set(Calendar.YEAR, season);
        opening.set(Calendar.MONTH, Calendar.MARCH);
        opening.set(Calendar.DAY_OF_MONTH, 20);
        zeroTime(opening);
        long days = Math.max(0L, Math.round((now.getTimeInMillis() - opening.getTimeInMillis()) / (24d * 60d * 60d * 1000d)));
        if (days < 21) return 20;
        if (days < 45) return 45;
        return 75;
    }

    private boolean isLiveHitterEligible(LeaderboardEntry e, Player p, HashSet<Integer> activeIds, int minPa) {
        if (e == null || e.stats == null || p == null || isPitcher(p)) return false;
        if (activeIds != null && !activeIds.isEmpty() && !activeIds.contains(e.playerId)) return false;
        return e.stats.pa >= Math.max(12, minPa);
    }

    private Player findPlayerByName(String name) {
        String target = normalizeNameKey(name);
        if (target.isEmpty()) return null;
        for (Player p : allPlayers) if (p != null && normalizeNameKey(p.fullName).equals(target)) return p;
        for (Player p : allPlayers) if (p != null && normalizeNameKey(p.fullName).contains(target)) return p;
        return null;
    }

    private Player playerFromEntry(LeaderboardEntry e) {
        if (e == null) return null;
        Player existing = findPlayerById(e.playerId);
        if (existing != null) return existing;
        return new Player(e.playerId, e.name, e.teamName, e.teamAbbr, "Hitter");
    }

    // v248: fetch and parse MLB's per-game win-probability feed into the LiveGame. The endpoint
    // returns an array of play entries, each carrying homeTeamWinProbability /
    // awayTeamWinProbability (0..100). We keep the home series for the trendline and the latest
    // values for the headline split. Defensive throughout — field names/shape are confirmed
    // on-device, and any parse failure simply leaves wpLoaded false so the UI hides the section.
    private void fetchWinProbabilityInto(LiveGame game) {
        if (game == null || game.gamePk <= 0) return;
        try {
            String url = "https://statsapi.mlb.com/api/v1/game/" + game.gamePk + "/winProbability";
            String body = game.isLive() ? httpGetFresh(url) : httpGet(url);
            if (body == null || body.isEmpty()) return;
            ArrayList<Float> homeSeries = new ArrayList<>();
            ArrayList<Integer> innings = new ArrayList<>();
            ArrayList<String> descriptions = new ArrayList<>();
            ArrayList<Float> swings = new ArrayList<>();
            float lastHome = -1f, lastAway = -1f;

            JSONArray plays = null;
            String trimmed = body.trim();
            if (trimmed.startsWith("[")) {
                plays = new JSONArray(trimmed);
            } else {
                JSONObject root = new JSONObject(trimmed);
                if (root.has("winProbability")) plays = root.optJSONArray("winProbability");
                else if (root.has("plays")) plays = root.optJSONArray("plays");
            }
            if (plays == null) return;

            float prevHome = -1f;
            for (int i = 0; i < plays.length(); i++) {
                JSONObject p = plays.optJSONObject(i);
                if (p == null) continue;
                double h = readWinProb(p, true);
                double a = readWinProb(p, false);
                if (h < 0 && a < 0) continue;
                if (h < 0 && a >= 0) h = 100d - a;
                if (a < 0 && h >= 0) a = 100d - h;
                lastHome = (float) h;
                lastAway = (float) a;
                homeSeries.add((float) h);

                // Inning + description live in the play's "about" / "result" blocks (confirmed
                // against the MLB feed schema). Default gracefully if absent.
                JSONObject about = p.optJSONObject("about");
                int inning = about != null ? about.optInt("inning", -1) : -1;
                innings.add(inning);
                JSONObject result = p.optJSONObject("result");
                String desc = result != null ? result.optString("description", "") : "";
                if (desc.isEmpty() && result != null) desc = result.optString("event", "");
                descriptions.add(desc);

                // Swing: prefer the feed's own homeTeamWinProbabilityAdded; otherwise derive it
                // from the change vs the previous play.
                double added = p.has("homeTeamWinProbabilityAdded")
                        ? Math.abs(p.optDouble("homeTeamWinProbabilityAdded", 0d))
                        : (prevHome < 0 ? 0d : Math.abs(h - prevHome));
                swings.add((float) added);
                prevHome = (float) h;
            }

            if (!homeSeries.isEmpty()) {
                game.wpHomeSeries = homeSeries;
                game.wpInnings = innings;
                game.wpDescriptions = descriptions;
                game.wpSwings = swings;
                game.wpHome = lastHome;
                game.wpAway = lastAway >= 0 ? lastAway : (100f - lastHome);
                game.wpLoaded = true;
            }
        } catch (Exception ignored) {
            // leave wpLoaded false; the WP section is simply not shown
        }
    }

    // Pulls a win-probability value (0..100) for home or away from a play object, tolerating the
    // two field layouts MLB has used. Returns -1 if absent.
    private double readWinProb(JSONObject play, boolean home) {
        String key = home ? "homeTeamWinProbability" : "awayTeamWinProbability";
        if (play.has(key)) return play.optDouble(key, -1d);
        JSONObject wp = play.optJSONObject("winProbability");
        if (wp != null && wp.has(key)) return wp.optDouble(key, -1d);
        return -1d;
    }

    private ArrayList<LiveGame> fetchTodayLiveGames() throws Exception {
        // v252: fetch the slate for the selected day (today + liveDayOffset), past or future.
        Calendar cal = Calendar.getInstance();
        cal.add(Calendar.DAY_OF_YEAR, liveDayOffset);
        String dateStr = new SimpleDateFormat("MM/dd/yyyy", Locale.US).format(cal.getTime());
        String url = "https://statsapi.mlb.com/api/v1/schedule?sportId=1&date=" + URLEncoder.encode(dateStr, "UTF-8") + "&hydrate=probablePitcher,linescore,team";
        // Live slates change every pitch; bypass the in-memory cache (which has no age check) so the
        // tiles reflect current scores/states instead of a stale snapshot from when they first loaded.
        boolean isToday = (liveDayOffset == 0);
        JSONObject root = new JSONObject(isToday ? httpGetFresh(url) : httpGet(url));
        ArrayList<LiveGame> out = new ArrayList<>();
        JSONArray dates = root.optJSONArray("dates");
        if (dates == null) return out;
        for (int d = 0; d < dates.length(); d++) {
            JSONObject dateObj = dates.optJSONObject(d);
            if (dateObj == null) continue;
            JSONArray games = dateObj.optJSONArray("games");
            if (games == null) continue;
            for (int i = 0; i < games.length(); i++) {
                JSONObject g = games.optJSONObject(i);
                if (g == null) continue;
                JSONObject teams = g.optJSONObject("teams");
                JSONObject awayNode = teams == null ? null : teams.optJSONObject("away");
                JSONObject homeNode = teams == null ? null : teams.optJSONObject("home");
                JSONObject awayTeam = awayNode == null ? null : awayNode.optJSONObject("team");
                JSONObject homeTeam = homeNode == null ? null : homeNode.optJSONObject("team");
                JSONObject status = g.optJSONObject("status");
                LiveGame live = new LiveGame();
                live.gamePk = g.optInt("gamePk", 0);
                live.gameDate = g.optString("gameDate", "");
                live.awayTeamId = awayTeam == null ? 0 : awayTeam.optInt("id", 0);
                live.homeTeamId = homeTeam == null ? 0 : homeTeam.optInt("id", 0);
                Team awayKnown = findTeamById(live.awayTeamId);
                Team homeKnown = findTeamById(live.homeTeamId);
                live.awayName = awayTeam == null ? "Away" : awayTeam.optString("name", "Away");
                live.homeName = homeTeam == null ? "Home" : homeTeam.optString("name", "Home");
                String awayApiAbbr = awayTeam == null ? "" : awayTeam.optString("abbreviation", awayTeam.optString("teamCode", ""));
                String homeApiAbbr = homeTeam == null ? "" : homeTeam.optString("abbreviation", homeTeam.optString("teamCode", ""));
                live.awayAbbr = canonicalMlbAbbr(live.awayTeamId, live.awayName, awayKnown == null ? awayApiAbbr : awayKnown.abbr);
                live.homeAbbr = canonicalMlbAbbr(live.homeTeamId, live.homeName, homeKnown == null ? homeApiAbbr : homeKnown.abbr);
                live.awayScore = awayNode == null ? -1 : awayNode.optInt("score", -1);
                live.homeScore = homeNode == null ? -1 : homeNode.optInt("score", -1);
                live.abstractState = status == null ? "" : status.optString("abstractGameState", "");
                live.detailedState = status == null ? "" : status.optString("detailedState", "");
                live.awayPitcher = pitcherName(awayNode == null ? null : awayNode.optJSONObject("probablePitcher"));
                live.homePitcher = pitcherName(homeNode == null ? null : homeNode.optJSONObject("probablePitcher"));
                live.awayRecord = recordFromNode(awayNode);
                live.homeRecord = recordFromNode(homeNode);
                // v332: capture live state from the hydrated linescore so in-progress tiles can show
                // inning · outs · baserunners. (This is the parser the tiles actually use — the
                // separate parseLiveGameScheduleNode is only used by the single-game refresh path.)
                JSONObject ls = g.optJSONObject("linescore");
                if (ls != null) {
                    live.sitInning = ls.optInt("currentInning", 0);
                    live.sitInningState = ls.optString("inningState", "");
                    live.sitOuts = ls.optInt("outs", 0);
                    JSONObject off = ls.optJSONObject("offense");
                    if (off != null) {
                        live.onFirst = off.optJSONObject("first") != null;
                        live.onSecond = off.optJSONObject("second") != null;
                        live.onThird = off.optJSONObject("third") != null;
                    }
                }
                out.add(live);
            }
        }
        sortGamesByStatus(out);
        return out;
    }

    // v329: order the slate so live action is always on top:
    //   1 in progress / delayed, 2 not started, 3 final, 4 postponed. Ties keep schedule order.
    private void sortGamesByStatus(ArrayList<LiveGame> games) {
        if (games == null) return;
        java.util.Collections.sort(games, (a, b) -> Integer.compare(gameStatusRank(a), gameStatusRank(b)));
    }
    private int gameStatusRank(LiveGame g) {
        if (g == null) return 5;
        String s = safe(g.detailedState).toLowerCase(Locale.US);
        if (s.isEmpty()) s = safe(g.abstractState).toLowerCase(Locale.US);
        if (s.contains("postpone")) return 4;
        if (s.contains("final") || s.contains("game over") || s.contains("completed")) return 3;
        if (s.contains("in progress") || s.contains("live") || s.contains("delay") || s.contains("warmup")) return 1;
        // scheduled / pre-game / everything else not-yet-started
        return 2;
    }

    private String pitcherName(JSONObject obj) {
        if (obj == null) return "";
        String full = obj.optString("fullName", "");
        if (!full.isEmpty()) return full;
        return obj.optString("name", "");
    }

    private String recordFromNode(JSONObject node) {
        if (node == null) return "";
        JSONObject rec = node.optJSONObject("leagueRecord");
        if (rec == null) return "";
        int w = rec.optInt("wins", -1), l = rec.optInt("losses", -1);
        return (w < 0 || l < 0) ? "" : (w + "-" + l);
    }

    // ── Today's games badge ─────────────────────────────────────────────────────────────────────

    private void fetchTodayGames() {
        io.execute(() -> {
            try {
                String today = new SimpleDateFormat("MM/dd/yyyy", Locale.US).format(new Date());
                String url = "https://statsapi.mlb.com/api/v1/schedule?sportId=1&date=" + today;
                String text = httpGet(url);
                JSONObject root = new JSONObject(text);
                JSONArray dates = root.optJSONArray("dates");
                int total = 0;
                if (dates != null && dates.length() > 0) {
                    JSONObject dateObj = dates.getJSONObject(0);
                    total = dateObj.optInt("totalGames", 0);
                }
                int gameCount = total;
                main.post(() -> {
                    if (liveBadge == null) return;
                    if (gameCount > 0) {
                        liveBadge.setText(gameCount + " games today");
                        liveBadge.setBackground(roundedStroke(Color.argb(60, 13, 178, 163), Color.argb(140, 13, 178, 163), 14, 1));
                    } else {
                        liveBadge.setText("Off day");
                        liveBadge.setBackground(roundedStroke(Color.argb(40, 255, 255, 255), Color.argb(92, 255, 255, 255), 14, 1));
                    }
                });
            } catch (Exception ignored) {}
        });
    }

    // ── Favorites (players + teams) ──────────────────────────────────────────────────────────────
    // v237: persistent favorites, modeled on the recents store. Players and teams are kept in
    // separate ordered lists so the home screen can surface "your" players and teams. Newest
    // favorited item sorts first; toggling an existing favorite removes it.

    private static final int MAX_FAVORITES = 12;
    private static final String PREFS_FAVORITES = "statcast_favorites_v237";

    private boolean isFavoritePlayer(int playerId) {
        SharedPreferences prefs = getSharedPreferences(PREFS_FAVORITES, MODE_PRIVATE);
        for (int i = 0; i < MAX_FAVORITES; i++) {
            if (String.valueOf(playerId).equals(prefs.getString("fpid_" + i, null))) return true;
        }
        return false;
    }

    private boolean isFavoriteTeam(int teamId) {
        SharedPreferences prefs = getSharedPreferences(PREFS_FAVORITES, MODE_PRIVATE);
        for (int i = 0; i < MAX_FAVORITES; i++) {
            if (String.valueOf(teamId).equals(prefs.getString("ftid_" + i, null))) return true;
        }
        return false;
    }

    // Returns the new favorite state (true = now a favorite).
    private boolean toggleFavoritePlayer(Player p) {
        if (p == null) return false;
        return toggleFavorite("fpid_", "fpname_", String.valueOf(p.id), p.fullName);
    }

    private boolean toggleFavoriteTeam(Team t) {
        if (t == null) return false;
        return toggleFavorite("ftid_", "ftname_", String.valueOf(t.id), t.name);
    }

    private boolean toggleFavorite(String idKey, String nameKey, String id, String name) {
        SharedPreferences prefs = getSharedPreferences(PREFS_FAVORITES, MODE_PRIVATE);
        ArrayList<String> ids = new ArrayList<>();
        ArrayList<String> names = new ArrayList<>();
        boolean wasFavorite = false;
        for (int i = 0; i < MAX_FAVORITES; i++) {
            String fid = prefs.getString(idKey + i, null);
            String fname = prefs.getString(nameKey + i, null);
            if (fid == null) continue;
            if (fid.equals(id)) { wasFavorite = true; continue; } // drop it (toggle off)
            ids.add(fid); names.add(fname);
        }
        boolean nowFavorite;
        if (wasFavorite) {
            nowFavorite = false;
        } else {
            ids.add(0, id); names.add(0, name); // newest first
            nowFavorite = true;
        }
        SharedPreferences.Editor ed = prefs.edit();
        for (int i = 0; i < MAX_FAVORITES; i++) {
            if (i < ids.size()) {
                ed.putString(idKey + i, ids.get(i));
                ed.putString(nameKey + i, names.get(i));
            } else {
                ed.remove(idKey + i);
                ed.remove(nameKey + i);
            }
        }
        ed.apply();
        return nowFavorite;
    }

    private ArrayList<Player> favoritePlayers() {
        SharedPreferences prefs = getSharedPreferences(PREFS_FAVORITES, MODE_PRIVATE);
        ArrayList<Player> out = new ArrayList<>();
        for (int i = 0; i < MAX_FAVORITES; i++) {
            String idStr = prefs.getString("fpid_" + i, null);
            if (idStr == null) continue;
            try {
                Player p = playerById(Integer.parseInt(idStr));
                if (p != null) out.add(p);
            } catch (Exception ignored) {}
        }
        return out;
    }

    private ArrayList<Team> favoriteTeams() {
        SharedPreferences prefs = getSharedPreferences(PREFS_FAVORITES, MODE_PRIVATE);
        ArrayList<Team> out = new ArrayList<>();
        for (int i = 0; i < MAX_FAVORITES; i++) {
            String idStr = prefs.getString("ftid_" + i, null);
            if (idStr == null) continue;
            try {
                Team t = findTeamById(Integer.parseInt(idStr));
                if (t != null) out.add(t);
            } catch (Exception ignored) {}
        }
        return out;
    }

    // ── Recent players ───────────────────────────────────────────────────────────────────────────

    private static final int MAX_RECENTS = 5;
    private static final String PREFS_RECENTS = "statcast_recents_v28";

    private void saveToRecents(Player p) {
        if (p == null) return;
        SharedPreferences prefs = getSharedPreferences(PREFS_RECENTS, MODE_PRIVATE);
        // Load existing as ordered list
        ArrayList<String> ids = new ArrayList<>();
        ArrayList<String> names = new ArrayList<>();
        for (int i = 0; i < MAX_RECENTS; i++) {
            String id = prefs.getString("rid_" + i, null);
            String name = prefs.getString("rname_" + i, null);
            if (id != null && !String.valueOf(p.id).equals(id)) { ids.add(id); names.add(name); }
        }
        ids.add(0, String.valueOf(p.id));
        names.add(0, p.fullName);
        SharedPreferences.Editor ed = prefs.edit();
        for (int i = 0; i < Math.min(MAX_RECENTS, ids.size()); i++) {
            ed.putString("rid_" + i, ids.get(i));
            ed.putString("rname_" + i, names.get(i));
        }
        ed.apply();
    }

    private void rebuildHomeFavorites() {
        if (homeFavoritesBox == null) return;
        homeFavoritesBox.removeAllViews();
        ArrayList<Player> favPlayers = allPlayers.isEmpty() ? new ArrayList<>() : favoritePlayers();
        ArrayList<Team> favTeams = favoriteTeams();
        if (favPlayers.isEmpty() && favTeams.isEmpty()) {
            homeFavoritesBox.setVisibility(View.GONE);
            return;
        }
        homeFavoritesBox.setVisibility(View.VISIBLE);

        LinearLayout card = verticalCard(22, new int[] { Color.rgb(7, 12, 22), Color.rgb(10, 16, 28) });
        card.setPadding(dp(14), dp(12), dp(14), dp(12));

        TextView eyebrow = text("FAVORITES", 10, Color.rgb(244, 192, 54), true);
        eyebrow.setLetterSpacing(0.22f);
        card.addView(eyebrow);

        TextView sub = text("Your pinned players and teams", 12, INK_DIM, false);
        LinearLayout.LayoutParams subLp = matchWrap();
        subLp.setMargins(0, dp(2), 0, dp(10));
        card.addView(sub, subLp);

        if (!favPlayers.isEmpty()) {
            card.addView(favoriteChipRow(favPlayers, true));
        }
        if (!favTeams.isEmpty()) {
            LinearLayout teamRow = favoriteChipRow(favTeams, false);
            LinearLayout.LayoutParams trLp = matchWrap();
            trLp.setMargins(0, favPlayers.isEmpty() ? 0 : dp(8), 0, 0);
            teamRow.setLayoutParams(trLp);
            card.addView(teamRow);
        }

        homeFavoritesBox.addView(card, matchWrap());
    }

    // Builds a horizontally-scrolling row of favorite chips. isPlayers=true → players, else teams.
    private LinearLayout favoriteChipRow(ArrayList<?> items, boolean isPlayers) {
        HorizontalScrollView scroller = new HorizontalScrollView(this);
        scroller.setHorizontalScrollBarEnabled(false);
        LinearLayout row = new LinearLayout(this);
        row.setOrientation(LinearLayout.HORIZONTAL);
        for (Object item : items) {
            String label;
            int accent;
            View.OnClickListener click;
            if (isPlayers) {
                final Player p = (Player) item;
                label = shortName(p.fullName);
                accent = Color.rgb(176, 119, 255);
                click = v -> {
                    teamMode = false;
                    selectedPlayer = p;
                    applySmartDefaultForSelection(p);
                    renderSelectionPreview();
                    openProfileForCurrentSelection();
                };
            } else {
                final Team t = (Team) item;
                label = t.abbr;
                TeamPalette pal = paletteForAbbr(t.abbr);
                accent = pal == null ? Color.rgb(244, 192, 54) : pal.primary;
                click = v -> openTeamFromFavorite(t);
            }
            TextView chip = text(label, 12, Color.WHITE, true);
            chip.setGravity(Gravity.CENTER);
            chip.setPadding(dp(13), dp(8), dp(13), dp(8));
            chip.setBackground(roundedGradientStroke(new int[] {
                    Color.argb(232, 8, 13, 22),
                    mixColor(accent, Color.rgb(8, 12, 20), 0.74f)
            }, 16, Color.argb(120, Color.red(accent), Color.green(accent), Color.blue(accent)), 1));
            chip.setContentDescription((isPlayers ? "Open player " : "Open team ") + label);
            makePremiumButton(chip, 16f);
            chip.setOnClickListener(click);
            LinearLayout.LayoutParams chipLp = new LinearLayout.LayoutParams(-2, -2);
            chipLp.setMargins(0, 0, dp(8), 0);
            row.addView(chip, chipLp);
        }
        scroller.addView(row);
        LinearLayout wrap = new LinearLayout(this);
        wrap.setOrientation(LinearLayout.VERTICAL);
        wrap.addView(scroller, matchWrap());
        return wrap;
    }

    private void openTeamFromFavorite(Team t) {
        if (t == null) return;
        teamMode = true;
        selectedTeam = t;
        if (teamSpinner != null) {
            int idx = allTeams.indexOf(t);
            if (idx >= 0) teamSpinner.setSelection(idx);
        }
        constrainSelectedMetricsToPlayerRole("both", true);
        renderSelectionPreview();
        openProfileForCurrentSelection();
    }

    private void rebuildRecentsBox() {
        if (recentsBox == null || allPlayers.isEmpty()) return;
        SharedPreferences prefs = getSharedPreferences(PREFS_RECENTS, MODE_PRIVATE);
        ArrayList<Player> recents = new ArrayList<>();
        for (int i = 0; i < MAX_RECENTS; i++) {
            String idStr = prefs.getString("rid_" + i, null);
            if (idStr == null) break;
            try {
                int id = Integer.parseInt(idStr);
                Player p = playerById(id);
                if (p != null) recents.add(p);
            } catch (Exception ignored) {}
        }
        recentsBox.removeAllViews();
        if (recents.isEmpty()) { recentsBox.setVisibility(View.GONE); return; }
        recentsBox.setVisibility(View.VISIBLE);
        recentsBox.setOrientation(LinearLayout.VERTICAL);

        TextView recentLabel = text("Recent", 10, MUTED, true);
        recentLabel.setLetterSpacing(0.10f);
        recentLabel.setPadding(dp(2), 0, 0, dp(4));
        recentsBox.addView(recentLabel);

        LinearLayout chipRow = new LinearLayout(this);
        chipRow.setOrientation(LinearLayout.HORIZONTAL);
        for (Player p : recents) {
            Button chip = new Button(this);
            chip.setText(p.fullName.split(" ").length > 1 ? p.fullName.split(" ")[p.fullName.split(" ").length - 1] : p.fullName);
            chip.setAllCaps(false);
            chip.setTextSize(12);
            chip.setTypeface(Typeface.DEFAULT_BOLD);
            chip.setTextColor(NAVY);
            chip.setMinHeight(0); chip.setMinWidth(0);
            chip.setPadding(dp(10), dp(6), dp(10), dp(6));
            chip.setBackground(roundedStroke(isDark ? Color.rgb(26, 38, 62) : Color.WHITE, isDark ? TEAL_DARK : LINE, 16, 1));
            chip.setForeground(ripple(isDark));
            chip.setContentDescription("Recent: " + p.fullName);
            LinearLayout.LayoutParams chipLp = new LinearLayout.LayoutParams(-2, -2);
            chipLp.setMargins(0, 0, dp(7), 0);
            chip.setOnClickListener(v -> {
                selectedPlayer = p;
                searchInput.setText("");
                searchInput.clearFocus();
                suggestionsList.setVisibility(View.GONE);
                applySmartDefaultForSelection(p);
                renderSelectionPreview();
                hideKeyboard();
                refreshAfterPrimarySelection();
            });
            chipRow.addView(chip, chipLp);
        }
        recentsBox.addView(chipRow, matchWrap());
    }

    // ── Metric glossary ──────────────────────────────────────────────────────────────────────────

    
    private void showMetricGlossary(Metric m) {
        if (m == null) return;
        String desc = metricDescription(m.key);
        LinearLayout panel = new LinearLayout(this);
        panel.setOrientation(LinearLayout.VERTICAL);
        panel.setPadding(dp(18), dp(14), dp(18), dp(16));
        panel.setBackground(roundedGradientStroke(new int[] {
                Color.rgb(4, 8, 16),
                Color.rgb(7, 15, 28),
                Color.rgb(5, 24, 40)
        }, 28, Color.argb(96, 96, 228, 222), 1));

        View handle = new View(this);
        handle.setBackground(rounded(Color.argb(92, 255, 255, 255), 99));
        LinearLayout.LayoutParams handleLp = new LinearLayout.LayoutParams(dp(44), dp(4));
        handleLp.gravity = Gravity.CENTER_HORIZONTAL;
        panel.addView(handle, handleLp);

        LinearLayout top = new LinearLayout(this);
        top.setOrientation(LinearLayout.HORIZONTAL);
        top.setGravity(Gravity.CENTER_VERTICAL);
        LinearLayout.LayoutParams topLp = matchWrap();
        topLp.setMargins(0, dp(12), 0, 0);
        TextView title = text(m.label, 20, INK, true);
        top.addView(title, new LinearLayout.LayoutParams(0, -2, 1));
        TextView type = text(m.group == null ? "Stat" : m.group.replace("Standard ", ""), 10, Color.rgb(174, 218, 255), true);
        type.setGravity(Gravity.CENTER);
        type.setPadding(dp(9), dp(4), dp(9), dp(4));
        type.setBackground(roundedStroke(Color.argb(24, 110, 190, 255), Color.argb(108, 110, 190, 255), 999, 1));
        top.addView(type);
        panel.addView(top, topLp);

        TextView eyebrow = text("WHAT IT MEANS", 9, Color.rgb(132, 150, 176), true);
        eyebrow.setLetterSpacing(0.10f);
        eyebrow.setPadding(0, dp(14), 0, dp(4));
        panel.addView(eyebrow, matchWrap());

        TextView body = text(desc, 13, INK_SOFT, false);
        body.setLineSpacing(dp(3), 1.0f);
        panel.addView(body, matchWrap());

        TextView read = text("HOW TO READ IT", 9, Color.rgb(132, 150, 176), true);
        read.setLetterSpacing(0.10f);
        read.setPadding(0, dp(14), 0, dp(4));
        panel.addView(read, matchWrap());

        String readText = m.higherGood == null ? "Context stat. Use it with related lens metrics." : (m.higherGood ? "Higher is better." : "Lower is better.");
        panel.addView(text(readText, 12, INK_SOFT, false), matchWrap());

        TextView used = text("USED IN", 9, Color.rgb(132, 150, 176), true);
        used.setLetterSpacing(0.10f);
        used.setPadding(0, dp(14), 0, dp(4));
        panel.addView(used, matchWrap());

        TextView usedBody = text(lensesForMetric(m), 12, INK_SOFT, false);
        usedBody.setPadding(0, 0, 0, dp(14));
        panel.addView(usedBody, matchWrap());

        TextView close = text("Done", 14, Color.rgb(8, 12, 20), true);
        close.setGravity(Gravity.CENTER);
        close.setPadding(dp(12), dp(10), dp(12), dp(10));
        close.setBackground(roundedGradient(new int[] { Color.rgb(255, 247, 174), Color.rgb(246, 198, 68), Color.rgb(226, 151, 28) }, 16));
        panel.addView(close, matchWrap());

        final AlertDialog dialog = new AlertDialog.Builder(this).create();
        dialog.setView(panel);
        close.setOnClickListener(v -> dialog.dismiss());
        makePremiumButton(close, 14f);  // v235: consistent press feedback
        dialog.show();
        try {
            android.view.Window w = dialog.getWindow();
            if (w != null) {
                w.setBackgroundDrawable(new android.graphics.drawable.ColorDrawable(Color.TRANSPARENT));
                w.setGravity(Gravity.BOTTOM);
                int maxH = (int) (getResources().getDisplayMetrics().heightPixels * 0.76f);
                w.setLayout(ViewGroup.LayoutParams.MATCH_PARENT, maxH);
            }
        } catch (Exception ignored) {}
    }


    private String lensesForMetric(Metric m) {
        if (m == null) return "All Stats";
        String role = "team".equals(m.side) ? "both" : m.side;
        StringBuilder out = new StringBuilder();
        for (String preset : presetOrderForRole(role)) {
            if ("luck".equals(preset) || "moreStats".equals(preset)) continue;
            LinkedHashSet<String> keys = metricKeysForPresetAndRole(preset, role);
            if (keys.contains(m.key)) {
                if (out.length() > 0) out.append(" · ");
                out.append(presetDisplayName(preset, role));
            }
        }
        if (out.length() == 0) out.append("All Stats");
        else if (out.indexOf("All") < 0) out.append(" · All Stats");
        return out.toString();
    }

    private String metricDescription(String key) {
        switch (key) {
            case "avg":    return "Batting Average — hits divided by at-bats. The classic measure of how often a batter gets a hit.";
            case "obp":    return "On-Base Percentage — how often a batter reaches base via hit, walk, or hit-by-pitch. Better than AVG because walks matter.";
            case "slg":    return "Slugging Percentage — total bases divided by at-bats. Rewards extra-base hits more than AVG.";
            case "ops":    return "On-Base Plus Slugging — OBP + SLG. A quick all-in-one offensive metric. League average is around .720.";
            case "hr":
            case "teamHR": return "Home Runs — total home runs hit in the season.";
            case "rbi":    return "Runs Batted In — how many runs a batter drove in. Affected by teammates and lineup spot.";
            case "r":      return "Runs Scored — how many times the batter crossed home plate.";
            case "sb":     return "Stolen Bases — successful steals of a base.";
            case "wOBA":   return "Weighted On-Base Average — like OBP but weights each way of reaching base by its run value. League average is around .320. One of the best offensive rate stats.";
            case "xwOBA":  return "Expected wOBA — what wOBA would be based purely on exit velocity and launch angle, ignoring luck, defense, and ballpark. Predicts future performance better than actual wOBA.";
            case "luck":   return "Luck (wOBA − xwOBA) — the gap between what actually happened and what the contact quality predicted. Positive means outperforming the ball-tracking; negative means underperforming it.";
            case "xBA":    return "Expected Batting Average — what AVG should be based on exit velocity and launch angle. Filters out luck and defense.";
            case "xSLG":   return "Expected Slugging — what SLG should be based on contact quality. Great for spotting hitters due for a power surge or correction.";
            case "avgEV":  return "Average Exit Velocity — average speed off the bat in mph across all balls in play. Higher is harder contact. Elite is 92+ mph.";
            case "avgLA":  return "Average Launch Angle — average vertical angle off the bat in degrees. 10–30° is the ideal 'sweet spot' range for line drives and home runs.";
            case "hardHitPct": return "Hard-Hit % — share of batted balls hit at 95+ mph. A proxy for raw power and contact quality. League average ~38%.";
            case "barrelPct":  return "Barrel % — share of batted balls that were both hard (95+ mph) AND in the ideal launch angle range. Barrels produce a .900+ slugging rate. Elite is 10%+.";
            case "sweetSpotPct": return "Sweet-Spot % — balls hit at 8–32° launch angle. That window produces the most hits and extra bases. Roughly corresponds to line drives.";
            case "kPct":   return "Strikeout % — share of plate appearances ending in a strikeout. Lower is better for hitters. League average ~22%.";
            case "bbPct":  return "Walk % — share of plate appearances ending in a walk. Higher is better. League average ~8.5%.";
            case "era":    return "Earned Run Average — earned runs allowed per 9 innings. The classic pitching summary stat. League average ~4.20.";
            case "whip":   return "Walks + Hits per Inning Pitched — measures baserunner traffic allowed. Lower is better. League average ~1.30.";
            case "k9":     return "Strikeouts per 9 innings — how often a pitcher misses bats. Elite starters reach 10+.";
            case "bb9":    return "Walks per 9 innings — control and command. Lower is better.";
            case "kbb":    return "K/BB ratio — strikeouts per walk. Combines stuff and command. Anything above 3.0 is excellent.";
            case "pitchK": return "Strikeouts — total batters struck out in the season.";
            case "pitchBB": return "Walks issued — total batters walked in the season.";
            case "saves":  return "Saves — a reliever earns a save by finishing a close win under specific conditions. Primarily tracks closers.";
            case "ip":     return "Innings Pitched — total innings a pitcher worked. Reflects workload and durability.";
            case "iso": return "Isolated Power — slugging minus batting average. Focuses on extra-base damage.";
            case "teamISO": return "Team ISO — team isolated power, focused on extra-base damage.";
            case "h": return "Hits — total hits recorded.";
            case "teamHits": return "Team hits — total hits recorded by the lineup.";
            case "doubles": case "teamDoubles": return "Doubles — total two-base hits.";
            case "triples": case "teamTriples": return "Triples — total three-base hits.";
            case "xbh": case "teamXbh": return "Extra-base hits — doubles, triples, and home runs.";
            case "bb": case "teamWalks": return "Walks — times reaching base on balls.";
            case "so": case "teamStrikeouts": return "Strikeouts — plate appearances ending in a strikeout.";
            case "tb": case "teamTB": return "Total Bases — one for a single, two for a double, three for a triple, four for a home run.";
            case "xOBP": case "teamXOBP": return "Expected OBP — expected on-base percentage from underlying events.";
            case "xISO": case "teamXISO": return "Expected ISO — expected extra-base power.";
            case "wOBAcon": return "wOBA on contact — production only when the ball is put in play.";
            case "xwOBAcon": return "Expected wOBA on contact — expected production on batted balls based on contact quality.";
            case "gbPct": case "teamGbPct": return "Ground-ball % — share of batted balls hit on the ground.";
            case "fbPct": case "teamFbPct": return "Fly-ball % — share of batted balls hit in the air.";
            case "ldPct": case "teamLdPct": return "Line-drive % — share of batted balls hit as line drives.";
            case "pullPct": case "teamPullPct": return "Pull % — share of batted balls hit to the pull side.";
            case "oppoPct": case "teamOppoPct": return "Opposite-field % — share of batted balls hit the other way.";
            case "bbMinusKPct": case "teamBBMinusKPct": return "BB-K % — walk rate minus strikeout rate. Quick plate discipline read.";
            case "whiffPct": case "teamWhiffPct": return "Whiff % — share of swings that miss.";
            case "swingPct": case "teamSwingPct": return "Swing % — share of pitches where the batter swings.";
            case "chasePct": case "teamChasePct": return "Chase % — swings at pitches outside the strike zone.";
            case "zoneContactPct": case "teamZoneContactPct": return "Zone Contact % — contact rate on pitches in the strike zone.";
            case "sprintSpeed": return "Sprint Speed — Statcast running speed in feet per second.";
            case "teamWinPct": return "Win % — team wins divided by games played.";
            case "teamRunsScored": return "Runs scored — total runs scored.";
            case "teamRunsAllowed": return "Runs allowed — total runs allowed.";
            case "teamRunDiff": return "Run differential — runs scored minus runs allowed.";
            case "teamRPG": return "Runs per game — average runs scored per game.";
            case "teamRAPG": return "Runs allowed per game — average runs allowed per game.";
            case "pitchKPct": case "teamPitchKPct": return "Pitching K % — share of batters struck out.";
            case "pitchBBPct": case "teamPitchBBPct": return "Pitching BB % — share of batters walked.";
            case "pitchKMinusBBPct": case "teamPitchKMinusBBPct": return "K-BB % — strikeout rate minus walk rate.";
            case "pHitsAllowed": case "teamHitsAllowed": return "Hits allowed — total hits allowed by pitchers.";
            case "pHrAllowed": case "teamHrAllowed": return "Home runs allowed — total home runs allowed.";
            case "pOppAvg": case "teamOppAvg": return "Opponent AVG — batting average allowed.";
            case "pOppOps": case "teamOppOps": return "Opponent OPS — on-base plus slugging allowed.";
            case "pxBA": case "teamPXBA": return "Expected AVG allowed — expected batting average allowed from contact quality.";
            case "pxSLG": case "teamPXSLG": return "Expected SLG allowed — expected slugging allowed from contact quality.";
            case "pwOBA": case "teamPWOBA": return "wOBA allowed — weighted on-base average allowed.";
            case "pxwOBA": case "teamPXWOBA": return "Expected wOBA allowed — expected weighted on-base average allowed.";
            case "pAvgEV": case "teamPAvgEV": return "Average exit velocity allowed — average contact speed allowed.";
            case "pHardHitPct": case "teamPHardHitPct": return "Hard-Hit % allowed — share of allowed batted balls hit 95+ mph.";
            case "pBarrelPct": case "teamPBarrelPct": return "Barrel % allowed — share of allowed batted balls barreled.";
            case "pWhiffPct": case "teamPWhiffPct": return "Pitching Whiff % — share of swings that miss.";
            case "pChasePct": case "teamPChasePct": return "Pitching Chase % — how often hitters chase pitches out of the zone.";
            case "pFirstStrikePct": case "teamPFirstStrikePct": return "First Strike % — how often pitchers start plate appearances with strike one.";
            case "pZonePct": case "teamPZonePct": return "Zone % — share of pitches thrown in the strike zone.";
            case "pGbPct": case "teamPGbPct": return "Ground-ball % allowed — share of allowed batted balls on the ground.";
            case "pFbPct": case "teamPFbPct": return "Fly-ball % allowed — share of allowed batted balls in the air.";
            case "pLdPct": case "teamPLdPct": return "Line-drive % allowed — share of allowed batted balls hit as line drives.";
            // v227: synthetic matchup-card metrics. These previously fell through to the weak
            // generic fallback, so tapping their "i" gave a non-answer. Each now explains what
            // the score means and how it's built, matching how it's used on the card.
            case "bpQualityScore": return "Bullpen Quality Score (0–100) — a rating of how good a bullpen's relievers are, blending their ERA, WHIP, K-BB%, and home runs allowed onto a single scale. Higher is better. Drives 70% of the bullpen matchup edge.";
            case "bpFreshnessScore": return "Bullpen Freshness Score (0–100) — how rested the bullpen is tonight, based on recent workload: innings over the last two days, back-to-back appearances, and heavily-used arms. Higher means fresher. Drives 30% of the bullpen matchup edge.";
            case "bpERA": return "Bullpen ERA — earned runs allowed per nine innings by the relievers only. Lower is better.";
            case "bpWHIP": return "Bullpen WHIP — walks plus hits per inning pitched by the relievers only. Lower is better.";
            case "bpKMinusBB": return "Bullpen K-BB% — strikeout rate minus walk rate for the relievers. A clean read on dominance and control in one number. Higher is better.";
            case "bpHR9": return "Bullpen HR/9 — home runs allowed per nine innings by the relievers. Lower is better.";
            case "bpStaffIP": return "Innings Last 2 Days — relief innings the bullpen has thrown over the past two calendar days. More recent work means more fatigue tonight.";
            case "bpB2B": return "Back-to-Back Arms — relievers pitching on consecutive days. More B2B arms means a more taxed bullpen.";
            case "bpWatchArms": return "Watch Arms — relievers flagged as fatigued from heavy recent use, worth watching for availability tonight.";
            case "bpSectionQuality": return "Quality drives 70% of the bullpen edge — it captures how good the relievers are, independent of how rested they are.";
            case "bpSectionFreshness": return "Freshness drives 30% of the bullpen edge — it captures tonight's availability, since even an elite bullpen is weaker when overworked.";
            case "ovsOverall": return "Matchup Score (0–100) — the overall edge in a lineup-vs-starter matchup, weighting the four factors below with the starter's quality carrying the most influence. Higher favors the offense.";
            case "ovsOnBase": return "On-Base Edge — how well the lineup reaches base (OBP, walk rate) against the starter's ability to limit baserunners. Higher favors the offense.";
            case "ovsPower": return "Power Edge — the lineup's extra-base power (SLG, barrels) against the starter's ability to suppress hard contact. Higher favors the offense.";
            case "ovsDiscipline": return "Discipline Edge — the lineup's strike-zone control (K avoidance, walk-vs-strikeout balance) against the starter's strikeout and swing-and-miss ability. Higher favors the offense.";
            case "ovsStarterVuln": return "Starter Stress — how vulnerable the starter looks overall (ERA, WHIP, expected wOBA, hard contact allowed). Higher means a more exploitable starter.";
            case "hbScore": return "Hot Bat Score — a rating of how well a hitter has been swinging recently, weighting recent production and contact quality. Higher means hotter.";
            case "babip": case "teamBABIP": return "Batting Average on Balls in Play — how often balls in play fall for hits. Often noisy; far from .300 can signal good or bad luck that may regress.";
            // v227: team metrics mirror their player counterparts. Route them to the same
            // descriptions so 40+ team rows stop showing the generic fallback.
            case "teamAVG": return metricDescription("avg");
            case "teamOBP": return metricDescription("obp");
            case "teamSLG": return metricDescription("slg");
            case "teamOPS": return metricDescription("ops");
            case "teamWOBA": return metricDescription("wOBA");
            case "teamXWOBA": return metricDescription("xwOBA");
            case "teamXBA": return metricDescription("xBA");
            case "teamXSLG": return metricDescription("xSLG");
            case "teamAvgEV": return metricDescription("avgEV");
            case "teamBarrelPct": return metricDescription("barrelPct");
            case "teamHardHitPct": return metricDescription("hardHitPct");
            case "teamSweetSpotPct": return metricDescription("sweetSpotPct");
            case "teamKPct": return metricDescription("kPct");
            case "teamBBPct": return metricDescription("bbPct");
            case "teamRBI": return metricDescription("rbi");
            case "teamSB": return metricDescription("sb");
            case "teamERA": return metricDescription("era");
            case "teamWHIP": return metricDescription("whip");
            case "teamK9": return metricDescription("k9");
            case "teamBB9": return metricDescription("bb9");
            case "teamKBB": return metricDescription("kbb");
            case "teamWalksAllowed": return metricDescription("pitchBB");
            case "teamPitchStrikeouts": return metricDescription("pitchK");
            case "pHr9": return "Home Runs per 9 — home runs allowed per nine innings. Lower is better.";
            default:       return genericMetricDescription(key);
        }
    }


    private String genericMetricDescription(String key) {
        Metric metric = metricByKey(key);
        if (metric == null) return "Stat used for comparison and trend context.";
        String direction = metric.higherGood == null ? "Use it as context." : (metric.higherGood ? "Higher is generally better." : "Lower is generally better.");
        return metric.label + " — " + (metric.group == null ? "Stat" : metric.group) + " metric. " + direction;
    }


    // ── Sparkline (season trend) ─────────────────────────────────────────────────────────────────

    private void renderSparklineRow(LinearLayout parent, LinkedHashMap<Integer, Stats> seasons, Metric m, TeamPalette palette) {
        ArrayList<Integer> years = new ArrayList<>(seasons.keySet());
        if (years.size() > 1 && years.get(0) > years.get(years.size() - 1)) {
            Collections.reverse(years); // sparklines read oldest → newest, left to right
        }
        ArrayList<TrendPoint> pts = new ArrayList<>();
        for (int y : years) {
            Double v = seasons.get(y) == null ? null : seasons.get(y).get(m.key);
            pts.add(new TrendPoint(String.valueOf(y), v));
        }
        renderTrendPointRow(parent, "Trend · seasons", pts, m, palette, "years");
    }


    private String shortTrendLabel(String raw) {
        String v = safe(raw).trim();
        if (v.isEmpty()) return "";
        try {
            if (v.matches("\\d{1,2}/\\d{1,2}")) {
                String[] p = v.split("/");
                int month = Integer.parseInt(p[0]);
                int day = Integer.parseInt(p[1]);
                String m = shortMonthName(month);
                if (!m.isEmpty()) return m + " " + day;
            }
            String normalized = v.replace("/", "-");
            if (normalized.matches("\\d{4}-\\d{2}-\\d{2}")) {
                String[] p = normalized.split("-");
                int month = Integer.parseInt(p[1]);
                int day = Integer.parseInt(p[2]);
                String m = shortMonthName(month);
                if (!m.isEmpty()) return m + " " + day;
            }
        } catch (Exception ignored) {}
        if (v.length() > 10 && v.charAt(4) == '-') return v.substring(5, 10);
        return v;
    }


    class TrendMonthSegment {
        final String month;
        final int start;
        final int end;
        TrendMonthSegment(String month, int start, int end) { this.month = month; this.start = start; this.end = end; }
    }

    class SeasonMonthTimelineView extends View {
        final ArrayList<String> labels;
        final ArrayList<TrendPoint> monthlyPoints;
        final Metric metric;
        final int accent;
        final Paint paint = new Paint(Paint.ANTI_ALIAS_FLAG);
        SeasonMonthTimelineView(Context ctx, ArrayList<String> labels, ArrayList<TrendPoint> monthlyPoints, Metric metric, int accent) {
            super(ctx);
            this.labels = labels == null ? new ArrayList<>() : labels;
            this.monthlyPoints = monthlyPoints;
            this.metric = metric;
            this.accent = accent;
        }
        @Override protected void onDraw(Canvas canvas) {
            super.onDraw(canvas);
            if (labels.size() < 2) return;
            ArrayList<TrendMonthSegment> segments = monthSegmentsForTrendLabels(labels);
            if (segments.isEmpty()) return;
            float w = getWidth(), h = getHeight();
            float padL = dp(8), padR = dp(54);
            float plotW = Math.max(1f, w - padL - padR);
            int n = labels.size();

            paint.setTypeface(tfBold);
            paint.setFontFeatureSettings("'tnum' 1");
            paint.setTextAlign(Paint.Align.CENTER);
            paint.setStrokeWidth(dp(1));
            for (int i = 0; i < segments.size(); i++) {
                TrendMonthSegment seg = segments.get(i);
                float x1 = padL + plotW * seg.start / (n - 1f);
                float x2 = padL + plotW * Math.max(seg.start, seg.end) / (n - 1f);
                if (i < segments.size() - 1) {
                    TrendMonthSegment next = segments.get(i + 1);
                    x2 = padL + plotW * next.start / (n - 1f);
                } else {
                    x2 = padL + plotW;
                }
                if (x2 < x1 + dp(18)) x2 = Math.min(padL + plotW, x1 + dp(18));
                float cx = (x1 + x2) / 2f;

                paint.setStyle(Paint.Style.FILL);
                paint.setColor(i % 2 == 0 ? Color.argb(30, 255, 255, 255) : Color.argb(14, 255, 255, 255));
                canvas.drawRoundRect(new RectF(x1 + dp(1), dp(1), x2 - dp(1), h - dp(2)), dp(9), dp(9), paint);

                paint.setStyle(Paint.Style.STROKE);
                paint.setColor(Color.argb(70, 255, 255, 255));
                canvas.drawLine(x1, 0, x1, h, paint);

                paint.setStyle(Paint.Style.FILL);
                paint.setTextSize(dp(9));
                paint.setColor(INK_SOFT);
                canvas.drawText(seg.month.toUpperCase(Locale.US), cx, dp(14), paint);

                Double value = monthlyValueForLabel(monthlyPoints, seg.month);
                String valueText = value == null || Double.isNaN(value) ? "—" : format(value, metric);
                float pillW = Math.min(Math.max(dp(38), paint.measureText(valueText) + dp(12)), Math.max(dp(28), x2 - x1 - dp(6)));
                RectF pill = new RectF(cx - pillW / 2f, dp(22), cx + pillW / 2f, dp(43));
                paint.setColor(Color.argb(92, Color.red(accent), Color.green(accent), Color.blue(accent)));
                canvas.drawRoundRect(pill, dp(10), dp(10), paint);
                paint.setStyle(Paint.Style.STROKE);
                paint.setColor(Color.argb(116, Color.red(accent), Color.green(accent), Color.blue(accent)));
                canvas.drawRoundRect(pill, dp(10), dp(10), paint);
                paint.setStyle(Paint.Style.FILL);
                paint.setTextSize(dp(10));
                paint.setColor(Color.WHITE);
                canvas.drawText(valueText, cx, dp(37), paint);
            }
            TrendMonthSegment last = segments.get(segments.size() - 1);
            float end = padL + plotW;
            paint.setStyle(Paint.Style.STROKE);
            paint.setColor(Color.argb(70, 255, 255, 255));
            canvas.drawLine(end, 0, end, h, paint);
        }
    }

    class SparklineView extends View {
        final ArrayList<Double> values;
        final ArrayList<String> labels;
        final Metric metric;
        final int lineColor;
        final String mode;
        final Paint paint = new Paint(Paint.ANTI_ALIAS_FLAG);

        SparklineView(Context ctx, ArrayList<Double> values, ArrayList<String> labels, Metric metric, int lineColor, String mode) {
            super(ctx);
            this.values = values;
            this.labels = labels;
            this.metric = metric;
            this.lineColor = lineColor;
            this.mode = mode == null ? "season" : mode;
        }

        @Override protected void onDraw(Canvas canvas) {
            super.onDraw(canvas);
            int n = values.size();
            if (n < 2) return;
            float w = getWidth(), h = getHeight();
            float padL = dp(8), padR = dp(54), padT = dp(12), padB = dp(8);

            double min = Double.MAX_VALUE, max = -Double.MAX_VALUE;
            for (Double v : values) {
                if (v != null && !Double.isNaN(v)) {
                    min = Math.min(min, v);
                    max = Math.max(max, v);
                }
            }
            if (min == Double.MAX_VALUE) return;
            if (max == min) { max = min + Math.max(Math.abs(min) * 0.02, 0.001); min = min - Math.max(Math.abs(min) * 0.02, 0.001); }
            double span = max - min;
            min -= span * 0.08;
            max += span * 0.08;
            double mid = (min + max) / 2.0;

            float plotW = w - padL - padR;
            float plotH = h - padT - padB;

            paint.setShader(null);

            // v167: season charts now have subtle month lanes that use the same x-scale
            // as the sparkline, so labels and monthly values line up with the grid.
            if ("season".equals(mode)) {
                ArrayList<TrendMonthSegment> segments = monthSegmentsForTrendLabels(labels);
                paint.setStyle(Paint.Style.FILL);
                for (int i = 0; i < segments.size(); i++) {
                    TrendMonthSegment seg = segments.get(i);
                    float x1 = padL + plotW * seg.start / (n - 1f);
                    float x2 = (i + 1 < segments.size())
                            ? padL + plotW * segments.get(i + 1).start / (n - 1f)
                            : padL + plotW;
                    paint.setColor(i % 2 == 0 ? Color.argb(20, 255, 255, 255) : Color.argb(8, 255, 255, 255));
                    canvas.drawRect(x1, padT, x2, padT + plotH, paint);
                }
            }

            paint.setStyle(Paint.Style.STROKE);
            paint.setStrokeWidth(dp(1));

            // v163/v167: structured trend modes get faint full-height guide lines.
            paint.setColor(Color.argb("season".equals(mode) ? 52 : 24, 255, 255, 255));
            ArrayList<Integer> guideIndices = guideIndicesForMode();
            for (Integer index : guideIndices) {
                if (index == null || index < 0 || index >= n) continue;
                float x = padL + (n <= 1 ? 0 : plotW * index / (n - 1f));
                canvas.drawLine(x, padT, x, padT + plotH, paint);
            }

            paint.setColor(INK);
            for (int i = 0; i < 3; i++) {
                float y = padT + plotH * i / 2f;
                canvas.drawLine(padL, y, padL + plotW, y, paint);
            }

            paint.setStyle(Paint.Style.FILL);
            paint.setTextSize(dp(8));
            paint.setTypeface(tfBold);                 // v29: weight ladder
            paint.setFontFeatureSettings("'tnum' 1");  // v29: tabular figures for axis values
            paint.setColor(EYEBROW);
            paint.setTextAlign(Paint.Align.LEFT);
            canvas.drawText(format(max, metric), padL + plotW + dp(5), padT + dp(3), paint);
            canvas.drawText(format(mid, metric), padL + plotW + dp(5), padT + plotH / 2f + dp(3), paint);
            canvas.drawText(format(min, metric), padL + plotW + dp(5), padT + plotH + dp(3), paint);

            ArrayList<float[]> pts = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                Double v = values.get(i);
                if (v == null || Double.isNaN(v)) continue;
                float x = padL + plotW * i / (n - 1);
                float y = padT + plotH - (float) ((v - min) / (max - min)) * plotH;
                pts.add(new float[]{x, y});
            }
            if (pts.size() < 2) return;

            Path area = new Path();
            area.moveTo(pts.get(0)[0], padT + plotH);
            for (float[] p : pts) area.lineTo(p[0], p[1]);
            area.lineTo(pts.get(pts.size() - 1)[0], padT + plotH);
            area.close();
            paint.setStyle(Paint.Style.FILL);
            paint.setShader(new LinearGradient(0, padT, 0, padT + plotH, Color.argb(52, Color.red(lineColor), Color.green(lineColor), Color.blue(lineColor)), Color.TRANSPARENT, Shader.TileMode.CLAMP));
            canvas.drawPath(area, paint);
            paint.setShader(null);

            paint.setStyle(Paint.Style.STROKE);
            paint.setStrokeWidth(dp(2));
            paint.setColor(lineColor);
            paint.setStrokeCap(Paint.Cap.ROUND);
            paint.setStrokeJoin(Paint.Join.ROUND);
            Path line = new Path();
            line.moveTo(pts.get(0)[0], pts.get(0)[1]);
            for (int i = 1; i < pts.size(); i++) line.lineTo(pts.get(i)[0], pts.get(i)[1]);
            canvas.drawPath(line, paint);

            // No point markers: the line represents a continuous rolling/cumulative trend.

            // v161: dates are rendered as normal TextViews below the chart.
            // Do not draw tiny canvas date labels here.
        }

        private ArrayList<Integer> guideIndicesForMode() {
            ArrayList<Integer> out = new ArrayList<>();
            if (labels == null || labels.isEmpty()) return out;

            if ("month".equals(mode) || "years".equals(mode)) {
                for (int i = 0; i < labels.size(); i++) {
                    String label = safe(labels.get(i)).trim();
                    if (!label.isEmpty()) out.add(i);
                }
                return out;
            }

            if ("season".equals(mode)) {
                String lastMonth = "";
                for (int i = 0; i < labels.size(); i++) {
                    String month = monthNameFromTrendLabel(labels.get(i));
                    if (month.isEmpty()) continue;
                    if (!month.equals(lastMonth)) {
                        out.add(i);
                        lastMonth = month;
                    }
                }
            }
            return out;
        }
    }

    // ── Share as image ───────────────────────────────────────────────────────────────────────────

    private void shareComparisonAsImage() {
        if (headerBox == null || headerBox.getChildCount() == 0) {
            Toast.makeText(this, "Run a profile first", Toast.LENGTH_SHORT).show();
            return;
        }
        // Render the profile card to a bitmap
        View card = headerBox.getChildAt(0);
        if (card.getWidth() <= 0) { copyCurrentTable(); return; }
        card.setDrawingCacheEnabled(true);
        card.buildDrawingCache(true);
        Bitmap src = card.getDrawingCache();
        if (src == null) { copyCurrentTable(); return; }
        Bitmap bmp = Bitmap.createBitmap(src);
        card.setDrawingCacheEnabled(false);

        try {
            // Write to app cache dir and share via file:// URI (API 24+ allows this for our own files)
            File shareDir = new File(getCacheDir(), "share");
            shareDir.mkdirs();
            File f = new File(shareDir, "statcast_card.png");
            FileOutputStream fos = new FileOutputStream(f);
            bmp.compress(Bitmap.CompressFormat.PNG, 100, fos);
            fos.close();

            // For sharing we use MediaStore to get a content URI without needing FileProvider
            String inserted = android.provider.MediaStore.Images.Media.insertImage(
                    getContentResolver(), bmp,
                    "Statcast_" + (lastComparison != null ? lastComparison.name.replaceAll("[^A-Za-z0-9]", "_") : "card"),
                    "Statcast Compare card");
            Uri shareUri = inserted != null ? Uri.parse(inserted) : null;

            if (shareUri != null) {
                String caption = lastHeadToHead != null
                        ? lastHeadToHead.nameA + " vs " + lastHeadToHead.nameB + " · " + lastHeadToHead.season + " Statcast"
                        : (lastComparison != null ? lastComparison.name + " · " + lastComparison.season + " Statcast" : "Statcast Compare");
                Intent share = new Intent(Intent.ACTION_SEND);
                share.setType("image/*");
                share.putExtra(Intent.EXTRA_STREAM, shareUri);
                share.putExtra(Intent.EXTRA_TEXT, caption);
                share.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);
                startActivity(Intent.createChooser(share, "Share stat card"));
            } else {
                copyCurrentTable();
                Toast.makeText(this, "Copied as text instead", Toast.LENGTH_SHORT).show();
            }
        } catch (Exception e) {
            copyCurrentTable();
            Toast.makeText(this, "Copied comparison as text", Toast.LENGTH_SHORT).show();
        }
    }

